INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('Dune', 'Frank Herbert', 'Guerra por un planeta desértico donde la especia otorga poder galáctico y visiones proféticas del futuro.', ARRAY['Ciencia Ficción','Aventura'], ARRAY['Space Opera'], 'https://covers.openlibrary.org/b/id/11481354-L.jpg', 4.9, '9788381881654', 'es', 688),
('Fundación', 'Isaac Asimov', 'Un matemático predice el colapso del imperio galáctico y trama un plan de mil años para salvarlo.', ARRAY['Ciencia Ficción'], ARRAY['Space Opera'], 'https://covers.openlibrary.org/b/id/12338424-L.jpg', 4.7, '9789875664586', 'es', 244),
('Yo, robot', 'Isaac Asimov', 'Nueve relatos donde las tres leyes de la robótica se rompen de formas que nadie vio venir.', ARRAY['Ciencia Ficción'], ARRAY['Robots'], 'https://covers.openlibrary.org/b/id/12385229-L.jpg', 4.5, '9780345331397', 'es', 320),
('El fin de la eternidad', 'Isaac Asimov', 'Una organización edita el tiempo para proteger a la humanidad. Un técnico se enamora y lo arruina todo.', ARRAY['Ciencia Ficción'], ARRAY['Viajes en el tiempo'], 'https://covers.openlibrary.org/b/id/13939161-L.jpg', 4.6, '9788491425755', 'es', 256),
('El marciano', 'Andy Weir', 'Un astronauta abandonado en Marte decide no morir. Su arma: ciencia, papas y humor negro.', ARRAY['Ciencia Ficción','Aventura'], ARRAY['Hard SF'], 'https://covers.openlibrary.org/b/id/11447888-L.jpg', 4.7, '9786155514142', 'es', 384),
('Proyecto Hail Mary', 'Andy Weir', 'Despierta solo en una nave sin recordar quién es. De su memoria depende salvar la Tierra.', ARRAY['Ciencia Ficción','Aventura'], ARRAY['Hard SF'], 'https://covers.openlibrary.org/b/id/11200092-L.jpg', 4.8, '9786257442398', 'es', 496),
('Guía del autoestopista galáctico', 'Douglas Adams', 'Demolieron la Tierra para construir una autopista espacial. Lo que sigue es el viaje más absurdo del cosmos.', ARRAY['Ciencia Ficción','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15153298-L.jpg', 4.7, '9788433973108', 'es', 216),
('El juego de Ender', 'Orson Scott Card', 'Un niño genio entrenado en batallas simuladas descubre que el juego nunca fue un juego.', ARRAY['Ciencia Ficción','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13704315-L.jpg', 4.7, '9788490245460', 'es', 368),
('Neuromante', 'William Gibson', 'Un hacker quemado recibe una última chance: robar a una inteligencia artificial que ya lo sabe todo.', ARRAY['Ciencia Ficción','Cyberpunk'], ARRAY['Cyberpunk'], 'https://covers.openlibrary.org/b/id/283860-L.jpg', 4.3, '9783608504880', 'es', 336),
('Snow Crash', 'Neal Stephenson', 'Repartidor de pizza de día, hacker legendario en el metaverso. Un virus digital empieza a matar mentes reales.', ARRAY['Ciencia Ficción','Cyberpunk'], ARRAY['Cyberpunk'], 'https://covers.openlibrary.org/b/id/392508-L.jpg', 4.3, '9783442424504', 'es', 440),
('La mano izquierda de la oscuridad', 'Ursula K. Le Guin', 'Un embajador llega a un planeta helado donde el género no existe. Nada lo preparó para entenderlos.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10618463-L.jpg', 4.5, '9785050040107', 'es', 336),
('Los desposeídos', 'Ursula K. Le Guin', 'Un físico brillante viaja entre dos mundos enemigos: uno anarquista y pobre, otro capitalista y brutal.', ARRAY['Ciencia Ficción','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6979680-L.jpg', 4.5, '9780060504007', 'es', 400),
('¿Sueñan los androides con ovejas eléctricas?', 'Philip K. Dick', 'Un cazarrecompensas persigue androides fugitivos y empieza a dudar de su propia humanidad.', ARRAY['Ciencia Ficción','Distopía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14120064-L.jpg', 4.5, '9788445004807', 'es', 272),
('Ubik', 'Philip K. Dick', 'Tras un atentado, la realidad empieza a degradarse. La única salida viene en aerosol.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5018327-L.jpg', 4.4, '9788834706107', 'es', 240),
('El hombre en el castillo', 'Philip K. Dick', 'Los nazis ganaron la guerra y se repartieron América. Pero un libro prohibido cuenta otra historia.', ARRAY['Ciencia Ficción','Distopía'], ARRAY['Ucronía'], 'https://covers.openlibrary.org/b/id/13661291-L.jpg', 4.2, '9788445006788', 'es', 288),
('Hyperion', 'Dan Simmons', 'Siete peregrinos viajan hacia una criatura que concede un deseo... o la muerte. Cada uno confiesa su historia.', ARRAY['Ciencia Ficción'], ARRAY['Space Opera'], 'https://covers.openlibrary.org/b/id/380332-L.jpg', 4.7, '9780553283686', 'es', 624),
('El problema de los tres cuerpos', 'Liu Cixin', 'Una física contacta una civilización alienígena. Su respuesta: ya vamos en camino.', ARRAY['Ciencia Ficción'], ARRAY['Hard SF'], 'https://covers.openlibrary.org/b/id/10526598-L.jpg', 4.5, '9788804686521', 'es', 416),
('El bosque oscuro', 'Liu Cixin', 'El universo es un bosque oscuro lleno de cazadores. Revelar tu posición es morir.', ARRAY['Ciencia Ficción'], ARRAY['Hard SF'], 'https://covers.openlibrary.org/b/id/12606697-L.jpg', 4.6, '9788413143767', 'es', 550),
('Flores para Algernon', 'Daniel Keyes', 'Una cirugía convierte a Charlie en genio. Su diario registra el ascenso... y lo que viene después.', ARRAY['Ciencia Ficción','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14562056-L.jpg', 4.6, '9788470021770', 'es', 288),
('La guerra de los mundos', 'H.G. Wells', 'Los marcianos aterrizan en Inglaterra y la civilización colapsa en días. El pánico original.', ARRAY['Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13499665-L.jpg', 4.3, '9788499083636', 'es', 192),
('La máquina del tiempo', 'H.G. Wells', 'Un inventor viaja al año 802.701 y descubre en qué se convirtió la humanidad. No es bonito.', ARRAY['Ciencia Ficción','Clásicos'], ARRAY['Viajes en el tiempo'], 'https://covers.openlibrary.org/b/id/13720965-L.jpg', 4.3, '9788477028802', 'es', 144),
('Solaris', 'Stanisław Lem', 'Un océano alienígena lee tu mente y materializa a tus muertos. Los científicos no lo soportan.', ARRAY['Ciencia Ficción','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12313764-L.jpg', 4.4, '9788020409980', 'es', 224),
('Crónicas marcianas', 'Ray Bradbury', 'La humanidad coloniza Marte y repite todos sus errores. Poesía disfrazada de ciencia ficción.', ARRAY['Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9346537-L.jpg', 4.6, '9783257208634', 'es', 336),
('Cita con Rama', 'Arthur C. Clarke', 'Un cilindro alienígena de cincuenta kilómetros entra al sistema solar. Tienen semanas para explorarlo.', ARRAY['Ciencia Ficción'], ARRAY['Hard SF'], 'https://covers.openlibrary.org/b/id/8706130-L.jpg', 4.4, NULL, 'es', 288),
('2001: Una odisea espacial', 'Arthur C. Clarke', 'Un monolito alienígena guía la evolución humana. Y la computadora de la nave tiene otros planes.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15170836-L.jpg', 4.5, NULL, 'es', 320),
('El fin de la infancia', 'Arthur C. Clarke', 'Alienígenas traen paz mundial a cambio de nada. La pregunta es qué esperan de nuestros hijos.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14550066-L.jpg', 4.5, '9788435004442', 'es', 272),
('Forastero en tierra extraña', 'Robert A. Heinlein', 'Un humano criado por marcianos regresa a la Tierra y funda algo entre religión y revolución.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14630668-L.jpg', 4.2, '9780450050770', 'es', 544),
('Tropas del espacio', 'Robert A. Heinlein', 'Guerra interestelar contra insectos gigantes y una pregunta incómoda: ¿qué vale tu ciudadanía?', ARRAY['Ciencia Ficción'], ARRAY['Militar'], 'https://covers.openlibrary.org/b/id/14630746-L.jpg', 4.1, '9780425029459', 'es', 336),
('La quinta estación', 'N.K. Jemisin', 'Un continente que muere en ciclos apocalípticos y una madre que puede partir la tierra con la mente.', ARRAY['Ciencia Ficción','Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8133598-L.jpg', 4.5, '9780316229296', 'es', 512),
('Klara y el Sol', 'Kazuo Ishiguro', 'Una amiga artificial observa el mundo humano con una fe conmovedora. Nadie la ve venir.', ARRAY['Ciencia Ficción','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10648686-L.jpg', 4.3, '9780571364886', 'es', 352),
('Nunca me abandones', 'Kazuo Ishiguro', 'Tres amigos crecen en un internado idílico. El motivo de su existencia te va a romper.', ARRAY['Ciencia Ficción','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7736049-L.jpg', 4.4, '9788467216226', 'es', 352),
('Recursión', 'Blake Crouch', 'Una tecnología permite revivir recuerdos... y reescribirlos. La realidad empieza a colapsar en bucles.', ARRAY['Ciencia Ficción','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8748478-L.jpg', 4.5, '9781524759780', 'es', 384),
('Materia oscura', 'Blake Crouch', 'Lo secuestran y despierta en una vida que no es suya. Cada decisión abre un universo distinto.', ARRAY['Ciencia Ficción','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7436634-L.jpg', 4.5, '9788416858217', 'es', 352),
('Exhalación', 'Ted Chiang', 'Nueve relatos que doblan el tiempo, la memoria y el libre albedrío. Ciencia ficción que se siente filosofía.', ARRAY['Ciencia Ficción','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8793546-L.jpg', 4.5, '9781101972083', 'es', 368),
('La historia de tu vida', 'Ted Chiang', 'Una lingüista aprende el idioma alienígena y con él, a ver su futuro completo. Origen de Arrival.', ARRAY['Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/524046-L.jpg', 4.5, '9780765304193', 'es', 304),
('El Señor de los Anillos', 'J.R.R. Tolkien', 'Un anillo para dominarlos a todos y un hobbit que carga el destino de la Tierra Media.', ARRAY['Fantasía','Épica'], ARRAY['Alta fantasía'], 'https://covers.openlibrary.org/b/id/13223383-L.jpg', 4.9, '9788445013359', 'es', 1392),
('El hobbit', 'J.R.R. Tolkien', 'Bilbo solo quería tomar el té. Trece enanos y un mago lo arrastran a robarle a un dragón.', ARRAY['Fantasía','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13223383-L.jpg', 4.8, '9788445013359', 'es', 320),
('El Silmarillion', 'J.R.R. Tolkien', 'La creación del mundo de Tolkien: dioses, elfos, joyas malditas y guerras que duran eras.', ARRAY['Fantasía','Épica'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/15096518-L.jpg', 4.4, '9788445016794', 'es', 480),
('El nombre del viento', 'Patrick Rothfuss', 'Un mago legendario cuenta su historia real: de niño de la calle a alumno prodigio y leyenda viva.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11480483-L.jpg', 4.8, '9780756413712', 'es', 880),
('El temor de un hombre sabio', 'Patrick Rothfuss', 'Kvothe deja la Universidad y el mundo se hace enorme: cortes, mercenarios, hadas y venganza.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13796224-L.jpg', 4.7, '9781473223721', 'es', 1200),
('Juego de tronos', 'George R.R. Martin', 'Siete reinos, un trono de hierro y familias dispuestas a todo. Aquí nadie está a salvo.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12324415-L.jpg', 4.8, '9786073128841', 'es', 800),
('Choque de reyes', 'George R.R. Martin', 'Cinco reyes reclaman un trono mientras un cometa rojo cruza el cielo. La guerra lo devora todo.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12324415-L.jpg', 4.7, '9786073128841', 'es', 920),
('El camino de los reyes', 'Brandon Sanderson', 'Un esclavo con pasado de cirujano, tormentas que arrasan continentes y espadas que cortan almas.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14658316-L.jpg', 4.8, '9783453317109', 'es', 1200),
('Palabras radiantes', 'Brandon Sanderson', 'Los Caballeros Radiantes renacen mientras una tormenta eterna se acerca. Sanderson en su máximo nivel.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14619840-L.jpg', 4.8, '9788413143958', 'es', 1300),
('El imperio final', 'Brandon Sanderson', 'El villano ganó hace mil años. Una banda de ladrones con magia de metales planea el golpe imposible.', ARRAY['Fantasía'], ARRAY['Mistborn'], 'https://covers.openlibrary.org/b/id/14658160-L.jpg', 4.7, '9788490192955', 'es', 688),
('El pozo de la ascensión', 'Brandon Sanderson', 'Mataron al tirano. Ahora toca lo difícil: gobernar sin que todo colapse en guerra y traición.', ARRAY['Fantasía'], ARRAY['Mistborn'], 'https://covers.openlibrary.org/b/id/13540548-L.jpg', 4.6, '9788418037276', 'es', 800),
('Elantris', 'Brandon Sanderson', 'Los dioses de una ciudad despertaron malditos. Un príncipe cae con ellos y se niega a rendirse.', ARRAY['Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14658083-L.jpg', 4.4, '9788580445046', 'es', 640),
('Harry Potter y la piedra filosofal', 'J.K. Rowling', 'Un huérfano descubre que es mago, que es famoso y que alguien lleva años queriendo matarlo.', ARRAY['Fantasía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15155833-L.jpg', 4.8, '9781781101315', 'es', 256),
('Harry Potter y el prisionero de Azkaban', 'J.K. Rowling', 'Un asesino escapa de la prisión mágica y va por Harry. Nada en este libro es lo que parece.', ARRAY['Fantasía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14631819-L.jpg', 4.8, '9788419275202', 'es', 360),
('American Gods', 'Neil Gaiman', 'Los dioses antiguos sobreviven olvidados en América y preparan una guerra contra los nuevos: internet, medios, dinero.', ARRAY['Fantasía'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/8494659-L.jpg', 4.6, '9780694525492', 'es', 640);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('Coraline', 'Neil Gaiman', 'Detrás de una puerta hay otra madre con botones por ojos. Quiere que Coraline se quede para siempre.', ARRAY['Fantasía','Terror'], ARRAY['Juvenil'], 'https://covers.openlibrary.org/b/id/14171421-L.jpg', 4.5, '9788374801171', 'es', 176),
('Stardust', 'Neil Gaiman', 'Un joven promete traer una estrella fugaz. El problema: la estrella está viva y no quiere ir.', ARRAY['Fantasía','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8216379-L.jpg', 4.4, '9781594970979', 'es', 288),
('El océano al final del camino', 'Neil Gaiman', 'Un hombre recuerda el estanque de su infancia que era un océano, y lo que salió de él.', ARRAY['Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15175457-L.jpg', 4.4, NULL, 'es', 240),
('Buenos presagios', 'Terry Pratchett y Neil Gaiman', 'Un ángel y un demonio le agarraron cariño a la Tierra y sabotean juntos el Apocalipsis.', ARRAY['Fantasía','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10482258-L.jpg', 4.7, '9780062934918', 'es', 448),
('Mort', 'Terry Pratchett', 'La Muerte contrata un aprendiz adolescente. Primer error: dejarlo hacer el trabajo solo una noche.', ARRAY['Fantasía','Humor'], ARRAY['Mundodisco'], 'https://covers.openlibrary.org/b/id/14648805-L.jpg', 4.5, '9780062225719', 'es', 320),
('¡Guardias! ¡Guardias!', 'Terry Pratchett', 'Una secta invoca un dragón para tomar la ciudad. Solo la guardia más inútil del mundo puede detenerlo.', ARRAY['Fantasía','Humor'], ARRAY['Mundodisco'], 'https://covers.openlibrary.org/b/id/13095550-L.jpg', 4.5, '9783442545339', 'es', 416),
('La historia interminable', 'Michael Ende', 'Bastian roba un libro y descubre que Fantasía se muere... y que el libro lo está leyendo a él.', ARRAY['Fantasía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10448326-L.jpg', 4.7, '9788420471549', 'es', 496),
('Momo', 'Michael Ende', 'Los Hombres Grises roban el tiempo de la gente. Solo una niña que sabe escuchar puede enfrentarlos.', ARRAY['Fantasía','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8574580-L.jpg', 4.6, '9788830401075', 'es', 272),
('El león, la bruja y el ropero', 'C.S. Lewis', 'Cuatro hermanos cruzan un armario hacia un reino congelado en invierno eterno por una bruja.', ARRAY['Fantasía','Juvenil'], ARRAY['Narnia'], 'https://covers.openlibrary.org/b/id/8441376-L.jpg', 4.7, '9788804436775', 'es', 224),
('Jonathan Strange y el señor Norrell', 'Susanna Clarke', 'Dos magos rivales devuelven la magia a la Inglaterra napoleónica y despiertan algo muy antiguo.', ARRAY['Fantasía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/525391-L.jpg', 4.4, '9781608190867', 'es', 800),
('Piranesi', 'Susanna Clarke', 'Un hombre vive solo en una casa infinita de estatuas y mareas. Las pistas dicen que alguien miente.', ARRAY['Fantasía','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10226290-L.jpg', 4.5, '9782221250242', 'es', 272),
('El ojo del mundo', 'Robert Jordan', 'Tres jóvenes de aldea huyen de criaturas de pesadilla. Uno de ellos podría salvar o romper el mundo.', ARRAY['Fantasía','Épica'], ARRAY['La Rueda del Tiempo'], 'https://covers.openlibrary.org/b/id/980232-L.jpg', 4.5, '9789574679508', 'es', 832),
('La voz de las espadas', 'Joe Abercrombie', 'Un bárbaro famoso, un torturador lisiado y un noble insufrible. La fantasía más cínica y adictiva.', ARRAY['Fantasía'], ARRAY['Grimdark'], 'https://covers.openlibrary.org/b/id/7374275-L.jpg', 4.5, '9788420699325', 'es', 576),
('Canción de sangre', 'Anthony Ryan', 'Entregado a una orden guerrera a los diez años, Vaelin se convierte en la espada más letal del reino.', ARRAY['Fantasía','Épica'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10562946-L.jpg', 4.6, '9782352947509', 'es', 704),
('Trono de cristal', 'Sarah J. Maas', 'Sacan a una asesina legendaria de prisión para competir por su libertad matando por el rey.', ARRAY['Fantasía','Romance'], ARRAY['Romantasy'], 'https://covers.openlibrary.org/b/id/13312488-L.jpg', 4.4, '9781619630345', 'es', 496),
('Una corte de rosas y espinas', 'Sarah J. Maas', 'Mata un lobo en el bosque y la arrastran a un reino de hadas letales. El fenómeno romantasy.', ARRAY['Fantasía','Romance'], ARRAY['Romantasy'], 'https://covers.openlibrary.org/b/id/13971621-L.jpg', 4.5, '9781678715045', 'es', 456),
('De sangre y cenizas', 'Jennifer L. Armentrout', 'Una Doncella destinada a los dioses rompe todas las reglas por un guardia con demasiados secretos.', ARRAY['Fantasía','Romance'], ARRAY['Romantasy'], 'https://covers.openlibrary.org/b/id/12528316-L.jpg', 4.3, '9788417854317', 'es', 656),
('El príncipe cruel', 'Holly Black', 'Una mortal criada entre hadas decide que si no puede ser una de ellas, las va a gobernar.', ARRAY['Fantasía','Juvenil'], ARRAY['Hadas'], 'https://covers.openlibrary.org/b/id/15125110-L.jpg', 4.4, '9788417390617', 'es', 448),
('Sombra y hueso', 'Leigh Bardugo', 'Una cartógrafa descubre un poder capaz de destruir la oscuridad que parte su país en dos.', ARRAY['Fantasía','Juvenil'], ARRAY['Grishaverse'], 'https://covers.openlibrary.org/b/id/13816048-L.jpg', 4.3, '9786051869346', 'es', 352),
('Seis de cuervos', 'Leigh Bardugo', 'Seis criminales imposibles de controlar, un atraco imposible de lograr. El heist perfecto con magia.', ARRAY['Fantasía','Aventura'], ARRAY['Grishaverse'], 'https://covers.openlibrary.org/b/id/12667417-L.jpg', 4.6, '9781536439427', 'es', 496),
('Eragon', 'Christopher Paolini', 'Un granjero encuentra un huevo de dragón y hereda una guerra contra un rey inmortal.', ARRAY['Fantasía','Aventura'], ARRAY['Dragones'], 'https://covers.openlibrary.org/b/id/13921600-L.jpg', 4.2, '9780739330944', 'es', 544),
('Un mago de Terramar', 'Ursula K. Le Guin', 'Un joven mago arrogante libera una sombra que lo perseguirá por todos los mares del mundo.', ARRAY['Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13617691-L.jpg', 4.4, '9780553137675', 'es', 240),
('Circe', 'Madeline Miller', 'La bruja desterrada de la mitología griega cuenta su propia versión. Los dioses no salen bien parados.', ARRAY['Fantasía'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/8739376-L.jpg', 4.6, '9780316556323', 'es', 416),
('La canción de Aquiles', 'Madeline Miller', 'La historia de amor entre Aquiles y Patroclo antes de Troya. Sabes cómo acaba y aun así duele.', ARRAY['Fantasía','Romance'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/7098465-L.jpg', 4.7, '9789603649823', 'es', 384),
('Un cuento oscuro', 'Naomi Novik', 'Cada diez años el Dragón se lleva a una chica de la aldea. Esta vez eligió a la equivocada.', ARRAY['Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7399665-L.jpg', 4.4, '9788408151487', 'es', 480),
('1984', 'George Orwell', 'Un régimen vigila hasta tus pensamientos. Winston intenta rebelarse desde adentro con lo único suyo: su mente.', ARRAY['Distopía','Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8745958-L.jpg', 4.8, '9781405862417', 'es', 352),
('Rebelión en la granja', 'George Orwell', 'Los animales expulsan al granjero para ser libres. Los cerdos aprenden rápido a ser humanos.', ARRAY['Distopía','Clásicos'], ARRAY['Sátira'], 'https://covers.openlibrary.org/b/id/13712713-L.jpg', 4.6, '9798479218262', 'es', 144),
('Un mundo feliz', 'Aldous Huxley', 'Nadie sufre, todos consumen, la felicidad es obligatoria. Un salvaje llega a arruinar la fiesta.', ARRAY['Distopía','Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12527373-L.jpg', 4.6, NULL, 'es', 288),
('Fahrenheit 451', 'Ray Bradbury', 'Los bomberos ya no apagan incendios: queman libros. Uno de ellos comete el error de leer.', ARRAY['Distopía','Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12993656-L.jpg', 4.7, '9788499895581', 'es', 264),
('El cuento de la criada', 'Margaret Atwood', 'En la república de Gilead las mujeres son propiedad del Estado. Offred recuerda cuando tenía nombre.', ARRAY['Distopía','Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14640672-L.jpg', 4.6, '9788466601832', 'es', 416),
('Los testamentos', 'Margaret Atwood', 'Quince años después, tres mujeres dentro y fuera de Gilead conspiran para derrumbarlo desde sus grietas.', ARRAY['Distopía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12366815-L.jpg', 4.4, '9786050972559', 'es', 512),
('Oryx y Crake', 'Margaret Atwood', 'El último humano recuerda cómo su mejor amigo, un genio, decidió reiniciar la especie.', ARRAY['Distopía','Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12507658-L.jpg', 4.3, '9789724146362', 'es', 448),
('Los juegos del hambre', 'Suzanne Collins', 'Veinticuatro adolescentes entran a la arena, uno sale vivo. Katniss se ofrece de voluntaria.', ARRAY['Distopía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12646537-L.jpg', 4.5, '9788427248465', 'es', 400),
('Divergente', 'Veronica Roth', 'Una sociedad dividida en facciones por personalidad. Tris no encaja en ninguna, y eso se paga con la vida.', ARRAY['Distopía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14636359-L.jpg', 4.2, '9782092532324', 'es', 496),
('El corredor del laberinto', 'James Dashner', 'Despierta sin memoria en un claro rodeado por un laberinto que cambia cada noche. Nadie ha salido.', ARRAY['Distopía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10464801-L.jpg', 4.2, '9780553511536', 'es', 384),
('Nosotros', 'Yevgueni Zamiatin', 'La distopía original que inspiró a Orwell: un Estado de cristal donde hasta el amor tiene horario.', ARRAY['Distopía','Ciencia Ficción','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5484189-L.jpg', 4.2, '9781523410644', 'es', 256),
('La naranja mecánica', 'Anthony Burgess', 'Alex ama la ultraviolencia y a Beethoven. El Estado tiene una cura que da más miedo que él.', ARRAY['Distopía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10693069-L.jpg', 4.4, NULL, 'es', 240),
('El señor de las moscas', 'William Golding', 'Niños varados en una isla sin adultos. La civilización dura menos de lo que crees.', ARRAY['Distopía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8684447-L.jpg', 4.4, '9780571371723', 'es', 288),
('La carretera', 'Cormac McCarthy', 'Un padre y su hijo cruzan un mundo en cenizas cargando el fuego. Devastador y hermoso.', ARRAY['Distopía','Drama'], ARRAY['Postapocalíptico'], 'https://covers.openlibrary.org/b/id/12794428-L.jpg', 4.5, '9788499083469', 'es', 304),
('Ensayo sobre la ceguera', 'José Saramago', 'Una epidemia de ceguera blanca revela lo que somos cuando nadie nos ve. Saramago sin anestesia.', ARRAY['Distopía','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/2270923-L.jpg', 4.6, '9788466312301', 'es', 384),
('La parábola del sembrador', 'Octavia E. Butler', 'En una California colapsada, una adolescente que siente el dolor ajeno funda una nueva fe.', ARRAY['Distopía','Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10466266-L.jpg', 4.4, '9781453263617', 'es', 368),
('Estación Once', 'Emily St. John Mandel', 'Una pandemia acaba con el mundo y una compañía de teatro itinerante insiste: sobrevivir no basta.', ARRAY['Distopía','Novela Contemporánea'], ARRAY['Postapocalíptico'], 'https://covers.openlibrary.org/b/id/7369961-L.jpg', 4.3, '9782743637552', 'es', 352),
('Ready Player One', 'Ernest Cline', 'La realidad es tan mala que todos viven en un videojuego. Dentro hay un tesoro y una cacería global.', ARRAY['Distopía','Ciencia Ficción','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8737626-L.jpg', 4.4, '9780307887436', 'es', 480),
('V de Vendetta', 'Alan Moore', 'En una Inglaterra fascista, un anarquista enmascarado convierte la venganza en revolución. Novela gráfica esencial.', ARRAY['Distopía'], ARRAY['Novela gráfica'], 'https://covers.openlibrary.org/b/id/12293384-L.jpg', 4.5, '9781852862916', 'es', 296),
('Battle Royale', 'Koushun Takami', 'Una clase entera despierta en una isla con una orden: matarse entre ellos hasta que quede uno.', ARRAY['Distopía','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/813816-L.jpg', 4.3, '9781421565989', 'es', 664),
('El dador', 'Lois Lowry', 'En una comunidad sin dolor ni colores, un niño recibe todos los recuerdos que borraron.', ARRAY['Distopía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8352502-L.jpg', 4.3, '9780613047920', 'es', 240),
('Delirium', 'Lauren Oliver', 'El amor es una enfermedad y a los dieciocho te curan. A Lena le faltaban 95 días.', ARRAY['Distopía','Romance'], ARRAY['Juvenil'], 'https://covers.openlibrary.org/b/id/6682232-L.jpg', 4, NULL, 'es', 448),
('Qualityland', 'Marc-Uwe Kling', 'Un país donde el algoritmo decide todo por ti. Sátira del futuro que ya estamos viviendo.', ARRAY['Distopía','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10478508-L.jpg', 4.2, '9783550201028', 'es', 384),
('El círculo', 'Dave Eggers', 'Una empresa tecnológica donde la privacidad es robo y compartirlo todo es virtud. Te va a incomodar.', ARRAY['Distopía','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8334682-L.jpg', 4, '9780241146484', 'es', 448),
('Espejismo', 'Hugh Howey', 'La humanidad vive en un silo subterráneo. Preguntar qué hay afuera se castiga con salir.', ARRAY['Distopía','Ciencia Ficción'], ARRAY['Silo'], 'https://covers.openlibrary.org/b/id/7295589-L.jpg', 4.4, '9788445001493', 'es', 576);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('Metro 2033', 'Dmitry Glukhovsky', 'Tras la guerra nuclear, Moscú sobrevive en los túneles del metro. Algo se mueve en la oscuridad.', ARRAY['Distopía','Terror'], ARRAY['Postapocalíptico'], 'https://covers.openlibrary.org/b/id/9931150-L.jpg', 4.3, '9781481845700', 'es', 544),
('Vox', 'Christina Dalcher', 'Las mujeres solo pueden decir cien palabras al día. Una científica decide gastar las suyas en pelear.', ARRAY['Distopía','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10376984-L.jpg', 4, '9780008300647', 'es', 384),
('La larga marcha', 'Stephen King', 'Cien chicos caminan sin parar. Bajar de velocidad tres veces significa morir. Gana el último en pie.', ARRAY['Distopía','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14653609-L.jpg', 4.3, '9780142427835', 'es', 384),
('El fugitivo', 'Stephen King', 'Un reality show donde el premio es sobrevivir treinta días mientras el país entero te caza.', ARRAY['Distopía','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14651762-L.jpg', 4.1, '9783896040992', 'es', 320),
('El país de las últimas cosas', 'Paul Auster', 'Anna busca a su hermano en una ciudad que se desintegra, donde hasta las palabras desaparecen.', ARRAY['Distopía','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/376765-L.jpg', 4.2, '9788435013444', 'es', 208),
('El nombre de la rosa', 'Umberto Eco', 'Monjes mueren en una abadía medieval y todas las pistas llevan a una biblioteca prohibida.', ARRAY['Misterio','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15023290-L.jpg', 4.5, NULL, 'es', 784),
('Y no quedó ninguno', 'Agatha Christie', 'Diez extraños invitados a una isla. Uno muere cada noche. El asesino está entre ellos.', ARRAY['Misterio','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11172296-L.jpg', 4.7, '9789752124394', 'es', 288),
('Asesinato en el Orient Express', 'Agatha Christie', 'Un asesinato en un tren atrapado en la nieve y doce sospechosos que no conocen a la víctima.', ARRAY['Misterio','Clásicos'], ARRAY['Poirot'], 'https://covers.openlibrary.org/b/id/11100465-L.jpg', 4.6, '9780060599973', 'es', 256),
('Muerte en el Nilo', 'Agatha Christie', 'Una heredera aparece muerta en un crucero por Egipto. Todos a bordo tenían motivos.', ARRAY['Misterio','Clásicos'], ARRAY['Poirot'], 'https://covers.openlibrary.org/b/id/14066646-L.jpg', 4.5, '9789504916123', 'es', 320),
('El asesinato de Roger Ackroyd', 'Agatha Christie', 'El caso que rompió las reglas de la novela policiaca. El final sigue siendo el más comentado del género.', ARRAY['Misterio','Clásicos'], ARRAY['Poirot'], 'https://covers.openlibrary.org/b/id/13151356-L.jpg', 4.6, '9780593639580', 'es', 288),
('Estudio en escarlata', 'Arthur Conan Doyle', 'El primer caso de Sherlock Holmes: un cadáver, una palabra escrita con sangre y cero pistas para todos menos él.', ARRAY['Misterio','Clásicos'], ARRAY['Sherlock Holmes'], 'https://covers.openlibrary.org/b/id/13574672-L.jpg', 4.4, '9788467860948', 'es', 176),
('El sabueso de los Baskerville', 'Arthur Conan Doyle', 'Una maldición familiar, un páramo con niebla y un perro demoniaco. Holmes no cree en fantasmas.', ARRAY['Misterio','Clásicos'], ARRAY['Sherlock Holmes'], 'https://covers.openlibrary.org/b/id/14279159-L.jpg', 4.5, '9788472540415', 'es', 256),
('Las aventuras de Sherlock Holmes', 'Arthur Conan Doyle', 'Doce casos del detective más famoso de la historia. La lógica como superpoder.', ARRAY['Misterio','Clásicos'], ARRAY['Sherlock Holmes'], 'https://covers.openlibrary.org/b/id/10547050-L.jpg', 4.6, '9788497945264', 'es', 320),
('La chica del tren', 'Paula Hawkins', 'Cada mañana observa a la pareja perfecta desde el tren. Un día la mujer desaparece y ella recuerda algo.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10597595-L.jpg', 4.1, '9788408141471', 'es', 496),
('Perdida', 'Gillian Flynn', 'Ella desaparece en su quinto aniversario y todo apunta al esposo. Nadie te ha mentido así.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12325093-L.jpg', 4.4, '9789877251883', 'es', 576),
('Heridas abiertas', 'Gillian Flynn', 'Una reportera vuelve a su pueblo a cubrir asesinatos de niñas y a enfrentar a su propia familia.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13556607-L.jpg', 4.2, '9788490627273', 'es', 384),
('La verdad sobre el caso Harry Quebert', 'Joël Dicker', 'Su mentor es acusado de un crimen de hace 33 años. Cada capítulo cambia la verdad entera.', ARRAY['Misterio','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7376287-L.jpg', 4.4, '9780698171121', 'es', 864),
('Los hombres que no amaban a las mujeres', 'Stieg Larsson', 'Un periodista caído y una hacker antisocial investigan una desaparición de hace cuarenta años.', ARRAY['Misterio','Thriller'], ARRAY['Millennium'], 'https://covers.openlibrary.org/b/id/13866405-L.jpg', 4.5, '9788423342723', 'es', 672),
('La chica que soñaba con una cerilla y un bidón de gasolina', 'Stieg Larsson', 'Lisbeth Salander es acusada de triple asesinato. Su pasado explota y arrasa con todo.', ARRAY['Misterio','Thriller'], ARRAY['Millennium'], 'https://covers.openlibrary.org/b/id/12329017-L.jpg', 4.5, '9788423343249', 'es', 752),
('El silencio de la ciudad blanca', 'Eva García Sáenz de Urturi', 'Asesinatos rituales regresan a Vitoria justo cuando el condenado por ellos sale de prisión.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7421057-L.jpg', 4.3, '9788498687033', 'es', 480),
('El guardián invisible', 'Dolores Redondo', 'Una inspectora vuelve a su pueblo del Baztán a cazar un asesino que el folclore llama basajaun.', ARRAY['Misterio','Thriller'], ARRAY['Trilogía del Baztán'], 'https://covers.openlibrary.org/b/id/9910039-L.jpg', 4.3, '9780007525348', 'es', 448),
('La sombra del viento', 'Carlos Ruiz Zafón', 'Un niño elige un libro en el Cementerio de los Libros Olvidados y alguien empieza a quemar cada copia.', ARRAY['Misterio','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10107644-L.jpg', 4.7, '9780297851196', 'es', 576),
('El juego del alma', 'Javier Castillo', 'Una chica aparece crucificada y una periodista recibe una polaroid con una pista imposible.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10724295-L.jpg', 4.2, '9781644733738', 'es', 464),
('La chica de nieve', 'Javier Castillo', 'Una niña desaparece en el desfile de Acción de Gracias. Años después llega una cinta VHS: está viva.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11953764-L.jpg', 4.3, '9781405960885', 'es', 496),
('La paciente silenciosa', 'Alex Michaelides', 'Mató a su esposo y no ha dicho una palabra en seis años. Su psicólogo necesita saber por qué.', ARRAY['Misterio','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9407338-L.jpg', 4.4, '9781409181613', 'es', 384),
('Los crímenes de la calle Morgue', 'Edgar Allan Poe', 'Dos mujeres asesinadas en un cuarto cerrado por dentro. Nace el primer detective de la literatura.', ARRAY['Misterio','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12328025-L.jpg', 4.3, '9788446041672', 'es', 144),
('El misterio de la cripta embrujada', 'Eduardo Mendoza', 'Un detective recién salido del manicomio investiga niñas desaparecidas. Hilarante y brillante a la vez.', ARRAY['Misterio','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4405151-L.jpg', 4.2, '9788432231490', 'es', 192),
('El club del crimen de los jueves', 'Richard Osman', 'Cuatro jubilados resuelven crímenes fríos por hobby, hasta que aparece un cadáver fresco en su puerta.', ARRAY['Misterio','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10459874-L.jpg', 4.2, '9788467060225', 'es', 448),
('Uno de nosotros miente', 'Karen M. McManus', 'Cinco entran a detención, cuatro salen vivos. Todos tenían secretos que el muerto iba a publicar.', ARRAY['Misterio','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12503935-L.jpg', 4.3, '9780525707219', 'es', 448),
('Pequeñas mentiras', 'Liane Moriarty', 'Madres perfectas, escuela perfecta, y un muerto en la noche de trivia. Nadie dice quién ni cómo.', ARRAY['Misterio','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10724129-L.jpg', 4.3, '9788580576795', 'es', 512),
('La cena', 'Herman Koch', 'Dos parejas cenan en un restaurante elegante para decidir qué hacer con lo que hicieron sus hijos.', ARRAY['Misterio','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8296378-L.jpg', 4, '9783462043471', 'es', 304),
('Los renglones torcidos de Dios', 'Torcuato Luca de Tena', 'Una investigadora se interna en un psiquiátrico fingiendo locura. O eso dice ella.', ARRAY['Misterio','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5299758-L.jpg', 4.6, '9788432053986', 'es', 416),
('La pregunta de sus ojos', 'Eduardo Sacheri', 'Un empleado judicial jubilado no puede soltar el caso que le marcó la vida entera. Ni el amor que calló.', ARRAY['Misterio','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12333138-L.jpg', 4.4, '9789875781894', 'es', 320),
('Rebeca', 'Daphne du Maurier', 'La nueva esposa llega a Manderley y descubre que la primera, muerta, sigue mandando en la casa.', ARRAY['Misterio','Clásicos','Romance'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/8238729-L.jpg', 4.5, '9780575052734', 'es', 448),
('La mujer de blanco', 'Wilkie Collins', 'Un encuentro nocturno con una mujer fugada de un asilo desata una conspiración de identidades robadas.', ARRAY['Misterio','Clásicos'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/4684227-L.jpg', 4.4, '9781090563545', 'es', 720),
('El psicoanalista', 'John Katzenbach', 'Feliz cumpleaños, doctor: tiene quince días para descubrir quién quiere destruirlo o alguien de su familia muere.', ARRAY['Thriller'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/12325169-L.jpg', 4.5, '9788466662482', 'es', 544),
('El silencio de los corderos', 'Thomas Harris', 'Para cazar a un asesino serial, una agente novata necesita la ayuda de otro: Hannibal Lecter.', ARRAY['Thriller','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8580475-L.jpg', 4.6, '9789683910011', 'es', 448),
('El dragón rojo', 'Thomas Harris', 'Un perfilador retirado vuelve para cazar a un asesino de familias. Su consultor favorito está preso.', ARRAY['Thriller','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6997898-L.jpg', 4.4, '9788440630148', 'es', 480),
('El código Da Vinci', 'Dan Brown', 'Un asesinato en el Louvre destapa un secreto que la Iglesia lleva dos mil años protegiendo.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9255229-L.jpg', 4.2, '9788497870801', 'es', 592),
('Ángeles y demonios', 'Dan Brown', 'Una sociedad secreta amenaza con volar el Vaticano con antimateria. Langdon tiene una noche para impedirlo.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11408459-L.jpg', 4.2, '9788417031275', 'es', 640),
('Misery', 'Stephen King', 'Un escritor despierta secuestrado por su fan número uno. Ella no acepta el final de su saga.', ARRAY['Thriller','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8259296-L.jpg', 4.5, '9789024512799', 'es', 400),
('La tapadera', 'John Grisham', 'Un abogado brillante consigue el trabajo soñado. El bufete paga demasiado bien para ser legal.', ARRAY['Thriller'], ARRAY['Legal'], 'https://covers.openlibrary.org/b/id/11581319-L.jpg', 4.2, '9780307392497', 'es', 512),
('No es país para viejos', 'Cormac McCarthy', 'Encuentra dos millones en el desierto y se los lleva. El hombre que los busca no negocia.', ARRAY['Thriller','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9296899-L.jpg', 4.4, '9788308053065', 'es', 320),
('El coleccionista', 'John Fowles', 'Colecciona mariposas hasta que gana la lotería y decide coleccionar algo más: a ella.', ARRAY['Thriller'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/13677958-L.jpg', 4.2, '9788416677801', 'es', 320),
('La pareja de al lado', 'Shari Lapena', 'Dejaron a la bebé sola con el monitor encendido. Al volver de la cena, la cuna está vacía.', ARRAY['Thriller'], ARRAY['Doméstico'], 'https://covers.openlibrary.org/b/id/8600080-L.jpg', 4.1, '9788491290650', 'es', 368),
('La mujer en la ventana', 'A.J. Finn', 'Una agorafóbica espía a sus vecinos y presencia un crimen. Nadie le cree, ni ella misma.', ARRAY['Thriller'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/12325817-L.jpg', 4, '9788466347440', 'es', 512),
('Reina roja', 'Juan Gómez-Jurado', 'Antonia Scott tiene el cerebro más privilegiado de Europa y cero ganas de usarlo. Hasta hoy.', ARRAY['Thriller','Misterio'], ARRAY['Antonia Scott'], 'https://covers.openlibrary.org/b/id/9256100-L.jpg', 4.5, '9788466667937', 'es', 568),
('Loba negra', 'Juan Gómez-Jurado', 'Antonia Scott vuelve a la cacería: una topo rusa, Marbella y un enemigo que siempre va un paso adelante.', ARRAY['Thriller','Misterio'], ARRAY['Antonia Scott'], 'https://covers.openlibrary.org/b/id/9330598-L.jpg', 4.4, '9788466666497', 'es', 552),
('Shutter Island', 'Dennis Lehane', 'Dos agentes investigan una fuga imposible en un psiquiátrico insular. La isla no los deja ir.', ARRAY['Thriller','Misterio'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/28990-L.jpg', 4.4, '9780063072930', 'es', 400),
('Mystic River', 'Dennis Lehane', 'Tres amigos de infancia, un trauma enterrado y un asesinato que los vuelve a juntar del peor modo.', ARRAY['Thriller','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/432349-L.jpg', 4.3, '9783548257969', 'es', 528);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('American Psycho', 'Bret Easton Ellis', 'Banquero de Wall Street de día, psicópata meticuloso de noche. Sátira brutal del capitalismo ochentero.', ARRAY['Thriller','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8401686-L.jpg', 4, '9780330372480', 'es', 512),
('El talento de Mr. Ripley', 'Patricia Highsmith', 'Tom Ripley quiere la vida de su amigo rico. Literal. Toda su vida.', ARRAY['Thriller','Clásicos'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/2198258-L.jpg', 4.3, '9781784876760', 'es', 336),
('Extraños en un tren', 'Patricia Highsmith', 'Dos desconocidos, un trato perfecto: yo mato a la tuya, tú matas al mío. Nadie sospecharía.', ARRAY['Thriller','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3326787-L.jpg', 4.3, '9788433920157', 'es', 320),
('La caza del Octubre Rojo', 'Tom Clancy', 'El capitán del submarino nuclear más avanzado de la URSS pone rumbo a Estados Unidos. ¿Deserta o ataca?', ARRAY['Thriller'], ARRAY['Espionaje'], 'https://covers.openlibrary.org/b/id/5257540-L.jpg', 4.3, '9789500413916', 'es', 656),
('El día del Chacal', 'Frederick Forsyth', 'Un asesino profesional sin nombre ni rostro acepta el contrato imposible: matar a De Gaulle.', ARRAY['Thriller'], ARRAY['Espionaje'], 'https://covers.openlibrary.org/b/id/77394-L.jpg', 4.4, '9780736614818', 'es', 464),
('El caso Bourne', 'Robert Ludlum', 'Lo rescatan del mar con amnesia, dos balas y una cuenta suiza. Medio mundo quiere matarlo.', ARRAY['Thriller'], ARRAY['Espionaje'], 'https://covers.openlibrary.org/b/id/12829197-L.jpg', 4.2, '9789501505672', 'es', 576),
('Verity', 'Colleen Hoover', 'Contratada para terminar la saga de una autora postrada, encuentra un manuscrito que confiesa lo impensable.', ARRAY['Thriller','Romance'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/8747160-L.jpg', 4.4, '9781538739723', 'es', 336),
('La desaparición de Stephanie Mailer', 'Joël Dicker', 'Veinte años después de resolver un cuádruple asesinato, una periodista les dice: se equivocaron de culpable.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8199504-L.jpg', 4.2, '9788466349857', 'es', 656),
('La asistenta', 'Freida McFadden', 'Acepta trabajar para una familia perfecta con un cuarto que cierra por fuera. El final es un latigazo.', ARRAY['Thriller'], ARRAY['Doméstico'], 'https://covers.openlibrary.org/b/id/15167772-L.jpg', 4.4, '9788491294283', 'es', 384),
('Detrás de sus ojos', 'Sarah Pinborough', 'Se enreda con su jefe y se hace amiga de la esposa. El triángulo esconde algo que no vas a adivinar.', ARRAY['Thriller'], ARRAY['Psicológico'], 'https://covers.openlibrary.org/b/id/10377377-L.jpg', 4.1, '9788491046899', 'es', 416),
('El día que se perdió la cordura', 'Javier Castillo', 'Un hombre camina con la cabeza decapitada de una chica. El caso rompe la mente de quien lo investiga.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8212251-L.jpg', 4.2, '9788466348997', 'es', 456),
('Parque Jurásico', 'Michael Crichton', 'Clonaron dinosaurios para un parque temático. La matemática del caos dice que esto acaba mal.', ARRAY['Thriller','Ciencia Ficción'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12882940-L.jpg', 4.4, '9780307348135', 'es', 480),
('A ciegas', 'Josh Malerman', 'Hay algo afuera que no puedes mirar: verlo te vuelve loco. Malorie huye río abajo, vendada, con dos niños.', ARRAY['Thriller','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7351898-L.jpg', 4.2, '9788445002346', 'es', 368),
('Sé lo que estás pensando', 'John Verdon', 'Piensa un número. El asesino ya lo sabía y lo dejó escrito en un sobre cerrado.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6590236-L.jpg', 4.3, '9788499181363', 'es', 512),
('Seis cuatro', 'Hideo Yokoyama', 'Un secuestro sin resolver de hace catorce años reaparece calcado. La policía esconde más que el criminal.', ARRAY['Thriller','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10552826-L.jpg', 4.1, '9788418796449', 'es', 656),
('Orgullo y prejuicio', 'Jane Austen', 'Él es insufriblemente orgulloso, ella brutalmente ingeniosa. El enemies-to-lovers original de 1813.', ARRAY['Romance','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13574150-L.jpg', 4.8, '9788469833346', 'es', 432),
('Emma', 'Jane Austen', 'Emma arregla la vida amorosa de todos menos la suya. Spoiler: se le da fatal.', ARRAY['Romance','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9278312-L.jpg', 4.5, '9781492836506', 'es', 512),
('Sentido y sensibilidad', 'Jane Austen', 'Dos hermanas, dos formas de amar: una con la cabeza, otra con el corazón en llamas.', ARRAY['Romance','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10450935-L.jpg', 4.5, '9788420453071', 'es', 416),
('Persuasión', 'Jane Austen', 'Hace ocho años la convencieron de rechazarlo. Él volvió rico, famoso y dolido. Segunda oportunidad.', ARRAY['Romance','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12824691-L.jpg', 4.6, '9798574450031', 'es', 288),
('Jane Eyre', 'Charlotte Brontë', 'Una institutriz pobre y firme se enamora de su empleador. La casa guarda un secreto que grita de noche.', ARRAY['Romance','Clásicos'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/8235363-L.jpg', 4.7, '9783423240321', 'es', 592),
('Cumbres borrascosas', 'Emily Brontë', 'Heathcliff y Catherine se aman con una intensidad que destruye a dos generaciones enteras.', ARRAY['Romance','Clásicos'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/12818862-L.jpg', 4.5, '9798788292847', 'es', 416),
('Forastera', 'Diana Gabaldon', 'Una enfermera de 1945 toca unas piedras en Escocia y despierta en 1743, casada con un highlander.', ARRAY['Romance','Historia'], ARRAY['Viajes en el tiempo'], 'https://covers.openlibrary.org/b/id/7314029-L.jpg', 4.6, '9788498382877', 'es', 880),
('El diario de Noa', 'Nicholas Sparks', 'Un hombre lee cada día la misma historia de amor a una mujer que ya no lo recuerda.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12338081-L.jpg', 4.3, '9788415729310', 'es', 256),
('Un paseo para recordar', 'Nicholas Sparks', 'El chico popular y la hija del pastor. Ella tiene un secreto que lo cambia absolutamente todo.', ARRAY['Romance','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7271098-L.jpg', 4.2, '9789500421041', 'es', 272),
('Bajo la misma estrella', 'John Green', 'Dos adolescentes con cáncer se enamoran con humor negro y cero lástima. Prepara pañuelos.', ARRAY['Romance','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14853661-L.jpg', 4.5, '9781514153383', 'es', 304),
('Buscando a Alaska', 'John Green', 'Miles busca su Gran Quizá en un internado y lo encuentra en la chica más impredecible del mundo.', ARRAY['Romance','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12614602-L.jpg', 4.3, '9780593109069', 'es', 304),
('Yo antes de ti', 'Jojo Moyes', 'La contratan para cuidar a un hombre que ya no quiere vivir. Ella decide demostrarle que se equivoca.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14419339-L.jpg', 4.4, '9780606322416', 'es', 400),
('Romper el círculo', 'Colleen Hoover', 'Lily ama a un hombre que se parece demasiado a su padre. La historia de amor que duele leer.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10473609-L.jpg', 4.4, '9788408258360', 'es', 384),
('Tal vez mañana', 'Colleen Hoover', 'Su novio la engaña con su mejor amiga. Su vecino músico le propone componer juntos la venganza perfecta.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9258886-L.jpg', 4.3, '9788408150275', 'es', 400),
('La hipótesis del amor', 'Ali Hazelwood', 'Una doctoranda besa a un profesor random para probar un punto. Era el tirano del departamento.', ARRAY['Romance'], ARRAY['Romcom'], 'https://covers.openlibrary.org/b/id/10601402-L.jpg', 4.3, '9789899096486', 'es', 416),
('Rojo, blanco y sangre azul', 'Casey McQuiston', 'El hijo de la presidenta de EE.UU. odia al príncipe de Inglaterra. El odio se les complica.', ARRAY['Romance'], ARRAY['LGBT+'], 'https://covers.openlibrary.org/b/id/9171544-L.jpg', 4.4, '9782018055524', 'es', 448),
('Heartstopper', 'Alice Oseman', 'Charlie y Nick se sientan juntos en clase. Lo que sigue es la historia más tierna del cómic actual.', ARRAY['Romance','Juvenil'], ARRAY['LGBT+','Novela gráfica'], 'https://covers.openlibrary.org/b/id/9020805-L.jpg', 4.6, '9781527225336', 'es', 288),
('Eleanor & Park', 'Rainbow Rowell', 'Dos inadaptados comparten asiento en el bus y cómics y música. Primer amor en su forma más pura.', ARRAY['Romance','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12917595-L.jpg', 4.2, '9786053437130', 'es', 336),
('Fangirl', 'Rainbow Rowell', 'Cath escribe fanfiction famosa pero la universidad real la aterra. Crecer sin dejar de ser tú.', ARRAY['Romance','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7316505-L.jpg', 4.2, '9781250030962', 'es', 464),
('El amor en los tiempos del cólera', 'Gabriel García Márquez', 'Florentino espera cincuenta y un años, nueve meses y cuatro días para volver a declararse.', ARRAY['Romance','Realismo Mágico','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10096404-L.jpg', 4.5, '9788467204360', 'es', 496),
('Un cuento perfecto', 'Elísabet Benavent', 'Una ejecutiva que lo tiene todo y un camarero que no quiere nada. Juntos rompen sus propios guiones.', ARRAY['Romance','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10095339-L.jpg', 4.2, '9788491291916', 'es', 592),
('Culpa mía', 'Mercedes Ron', 'Noah se muda con el hijastro que no pidió: arrogante, peligroso y prohibido. El fenómeno Wattpad.', ARRAY['Romance','Juvenil'], ARRAY['Wattpad'], 'https://covers.openlibrary.org/b/id/10512957-L.jpg', 4.1, '9782016269596', 'es', 528),
('A través de mi ventana', 'Ariana Godoy', 'Raquel lleva años enamorada de su vecino Ares. Él ni la mira... hasta que le roba el wifi.', ARRAY['Romance','Juvenil'], ARRAY['Wattpad'], 'https://covers.openlibrary.org/b/id/11175935-L.jpg', 4, '9786073823555', 'es', 400),
('Boulevard', 'Flor M. Salvador', 'Hasta las flores más bonitas crecen en los boulevards más rotos. El libro que rompió a Latinoamérica.', ARRAY['Romance','Juvenil'], ARRAY['Wattpad'], 'https://covers.openlibrary.org/b/id/10879112-L.jpg', 4, '9789807909068', 'es', 368),
('Antes de diciembre', 'Joana Marcús', 'Un acuerdo con fecha de caducidad: enamorarse estaba fuera del plan. Diciembre llega igual.', ARRAY['Romance','Juvenil'], ARRAY['Wattpad'], 'https://covers.openlibrary.org/b/id/12080400-L.jpg', 4.1, '9788418483448', 'es', 544),
('Gente normal', 'Sally Rooney', 'Connell y Marianne se orbitan durante años sin saber estar juntos ni separados. Dolorosamente real.', ARRAY['Romance','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8794265-L.jpg', 4.2, '9780571347292', 'es', 288),
('Los puentes de Madison', 'Robert James Waller', 'Cuatro días con un fotógrafo de paso le alcanzan a Francesca para cuestionar toda una vida.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3344535-L.jpg', 4.1, '9789500424165', 'es', 192),
('Posdata: te quiero', 'Cecelia Ahern', 'Su esposo murió, pero dejó diez cartas para enseñarle a vivir sin él. Cada una firma igual.', ARRAY['Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4995410-L.jpg', 4.2, '9781401383312', 'es', 512),
('El diario de Bridget Jones', 'Helen Fielding', 'Soltera, treintañera y desastre profesional documenta su año entre dos hombres y mil propósitos fallidos.', ARRAY['Romance','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14156974-L.jpg', 4.1, '9788408121893', 'es', 320),
('Llámame por tu nombre', 'André Aciman', 'Un verano italiano de los ochenta, una casa junto al mar y un deseo que marca la vida entera.', ARRAY['Romance','Novela Contemporánea'], ARRAY['LGBT+'], 'https://covers.openlibrary.org/b/id/12325251-L.jpg', 4.3, '9789877384628', 'es', 336),
('Aristóteles y Dante descubren los secretos del universo', 'Benjamin Alire Sáenz', 'Dos chicos mexicoamericanos se encuentran en una alberca y se enseñan a nombrar lo que sienten.', ARRAY['Romance','Juvenil'], ARRAY['LGBT+'], 'https://covers.openlibrary.org/b/id/12327052-L.jpg', 4.4, '9789504947554', 'es', 400),
('Yo, Simon, Homo Sapiens', 'Becky Albertalli', 'Simon tiene un romance anónimo por email hasta que alguien lo descubre y lo chantajea.', ARRAY['Romance','Juvenil'], ARRAY['LGBT+'], 'https://covers.openlibrary.org/b/id/12303551-L.jpg', 4.3, '9780062839701', 'es', 320),
('Todo lo que nunca fuimos', 'Alice Kellen', 'Ella perdió a sus padres y las ganas de pintar. Axel, el amigo prohibido de la familia, la reconstruye.', ARRAY['Romance','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10523813-L.jpg', 4.2, '9788408221951', 'es', 448),
('Nosotros en la luna', 'Alice Kellen', 'Se conocen una noche en París y se escriben durante años. La distancia también es una historia de amor.', ARRAY['Romance','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10197442-L.jpg', 4.2, '9786070774249', 'es', 560),
('Lo que el viento se llevó', 'Margaret Mitchell', 'Scarlett O''Hara sobrevive a la guerra civil a puro egoísmo magnético. Rhett la ve tal como es.', ARRAY['Romance','Historia','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10527475-L.jpg', 4.5, '9798624723818', 'es', 1088);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('Así habló Zaratustra', 'Friedrich Nietzsche', 'Un profeta baja de la montaña a anunciar que Dios ha muerto y que puedes ser algo más.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/2290835-L.jpg', 4.3, '9788493037796', 'es', 448),
('Más allá del bien y del mal', 'Friedrich Nietzsche', 'Nietzsche demoliendo toda la filosofía anterior a martillazos. Incómodo, brillante, imposible de ignorar.', ARRAY['Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4910600-L.jpg', 4.3, '9789684329270', 'es', 304),
('El mundo de Sofía', 'Jostein Gaarder', 'Una chica de catorce años recibe cartas anónimas que le enseñan toda la filosofía. Y algo raro pasa.', ARRAY['Filosofía','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1048142-L.jpg', 4.4, '9788441502284', 'es', 640),
('Meditaciones', 'Marco Aurelio', 'El diario privado del emperador más poderoso del mundo. Dos mil años después sigue siendo terapia.', ARRAY['Filosofía','Clásicos'], ARRAY['Estoicismo'], 'https://covers.openlibrary.org/b/id/10469464-L.jpg', 4.6, '9788416540129', 'es', 224),
('Sobre la brevedad de la vida', 'Séneca', 'No tenemos poca vida: la desperdiciamos. Séneca te regaña desde hace veinte siglos y tiene razón.', ARRAY['Filosofía','Clásicos'], ARRAY['Estoicismo'], 'https://covers.openlibrary.org/b/id/13454302-L.jpg', 4.5, '9788417134730', 'es', 128),
('Manual de vida', 'Epicteto', 'Un esclavo se volvió el filósofo más libre de Roma. Su manual cabe en un bolsillo y cambia vidas.', ARRAY['Filosofía','Clásicos'], ARRAY['Estoicismo'], 'https://covers.openlibrary.org/b/id/13666114-L.jpg', 4.4, '9788476516737', 'es', 96),
('La República', 'Platón', '¿Qué es la justicia? Platón construye la ciudad ideal y de paso inventa la caverna más famosa del pensamiento.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14083732-L.jpg', 4.4, '9788497941464', 'es', 512),
('Apología de Sócrates', 'Platón', 'Sócrates ante el tribunal que lo condenará a muerte, defendiendo el derecho a hacer preguntas incómodas.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14398204-L.jpg', 4.6, '9780343043568', 'es', 96),
('Ética a Nicómaco', 'Aristóteles', 'Aristóteles responde la única pregunta que importa: qué es una vida buena y cómo se consigue.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10540191-L.jpg', 4.3, '9788420671673', 'es', 400),
('El príncipe', 'Nicolás Maquiavelo', 'El manual del poder sin moralina: cómo conseguirlo, conservarlo y por qué te van a odiar igual.', ARRAY['Filosofía','Historia','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12328579-L.jpg', 4.3, '9788417181161', 'es', 160),
('Ensayos', 'Michel de Montaigne', 'Un noble francés se encierra en su torre a escribir sobre sí mismo e inventa un género entero.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/2270551-L.jpg', 4.4, '9788441405523', 'es', 592),
('Discurso del método', 'René Descartes', 'Descartes duda de todo lo dudable hasta quedarse con una sola certeza: pienso, luego existo.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3348569-L.jpg', 4.2, '9788420617367', 'es', 128),
('Crítica de la razón pura', 'Immanuel Kant', 'El libro que partió la filosofía en dos: qué podemos conocer y qué nos queda grande para siempre.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13221708-L.jpg', 4.2, '9789500392549', 'es', 768),
('El existencialismo es un humanismo', 'Jean-Paul Sartre', 'Estás condenado a ser libre: nadie va a decidir por ti. Sartre explicado por Sartre en una conferencia.', ARRAY['Filosofía'], ARRAY['Existencialismo'], 'https://covers.openlibrary.org/b/id/9825014-L.jpg', 4.2, '9788435027038', 'es', 112),
('La náusea', 'Jean-Paul Sartre', 'Un historiador descubre que la existencia es absurda y le da náusea literal. Novela filosófica fundacional.', ARRAY['Filosofía','Clásicos'], ARRAY['Existencialismo'], 'https://covers.openlibrary.org/b/id/13222534-L.jpg', 4.2, '9786074153101', 'es', 256),
('El mito de Sísifo', 'Albert Camus', 'La vida es absurda, ¿y entonces qué? Camus responde por qué vale la pena vivirla igual.', ARRAY['Filosofía'], ARRAY['Existencialismo'], 'https://covers.openlibrary.org/b/id/12726570-L.jpg', 4.4, '9781517407308', 'es', 192),
('El arte de la guerra', 'Sun Tzu', 'Estrategia china de hace 2500 años que hoy citan CEOs, generales y tu entrenador de fútbol.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13723515-L.jpg', 4.3, '9788498797022', 'es', 160),
('Tao Te Ching', 'Lao Tsé', 'Ochenta y un poemas breves sobre fluir en vez de forzar. El libro más traducido después de la Biblia.', ARRAY['Filosofía','Poesía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/662232-L.jpg', 4.4, '9781984055767', 'es', 176),
('Siddhartha', 'Hermann Hesse', 'Un joven brahmán lo abandona todo para buscar la iluminación. La encuentra donde nadie la buscaría.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6562535-L.jpg', 4.5, '9780497260309', 'es', 208),
('Vigilar y castigar', 'Michel Foucault', 'Del suplicio público a la cárcel moderna: cómo el poder aprendió a vigilarte sin tocarte.', ARRAY['Filosofía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4925716-L.jpg', 4.3, '9789682301179', 'es', 384),
('La sociedad del cansancio', 'Byung-Chul Han', 'Ya no te explota un jefe: te explotas tú solo creyendo que es libertad. El filósofo del burnout.', ARRAY['Filosofía'], ARRAY['Actualidad'], NULL, 4.2, NULL, 'es', 128),
('En el enjambre', 'Byung-Chul Han', 'Qué nos hace el celular: indignación sin acción, ruido sin respeto, multitud sin nosotros.', ARRAY['Filosofía'], ARRAY['Actualidad'], 'https://covers.openlibrary.org/b/id/14550155-L.jpg', 4.1, '9788425433689', 'es', 112),
('Ética para Amador', 'Fernando Savater', 'Un padre le explica a su hijo adolescente qué es la libertad, sin sermones. Clásico de prepa que sí vale.', ARRAY['Filosofía','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10450866-L.jpg', 4.2, '9788434411982', 'es', 192),
('El arte de amar', 'Erich Fromm', 'Amar no es suerte ni química: es una habilidad que se aprende. Fromm te enseña la teoría.', ARRAY['Filosofía','Psicología'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4741809-L.jpg', 4.4, '9783548221656', 'es', 192),
('Walden', 'Henry David Thoreau', 'Se fue a vivir solo al bosque dos años para averiguar qué es esencial. El manifiesto anti-ruido original.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11248037-L.jpg', 4.2, '9783150204733', 'es', 368),
('Sobre la libertad', 'John Stuart Mill', 'Hasta dónde puede meterse la sociedad con tu vida: la defensa más elegante de pensar distinto.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12104135-L.jpg', 4.3, '9788430947058', 'es', 208),
('El contrato social', 'Jean-Jacques Rousseau', 'El hombre nace libre y en todas partes está encadenado. El libro que encendió revoluciones.', ARRAY['Filosofía','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13531565-L.jpg', 4.2, '9788441431935', 'es', 224),
('Cándido', 'Voltaire', 'Un optimista incurable recorre un mundo de desastres. La sátira filosófica más ácida del siglo XVIII.', ARRAY['Filosofía','Clásicos','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13896467-L.jpg', 4.3, '9781412141925', 'es', 160),
('Justicia', 'Michael J. Sandel', 'Dilemas imposibles del curso más famoso de Harvard: ¿matarías a uno para salvar a cinco?', ARRAY['Filosofía','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14091975-L.jpg', 4.4, '9788499894140', 'es', 352),
('Cómo ser un estoico', 'Massimo Pigliucci', 'Filosofía antigua aplicada a tráfico, redes sociales y ansiedad moderna. Estoicismo sin humo.', ARRAY['Filosofía','Educación'], ARRAY['Estoicismo'], 'https://covers.openlibrary.org/b/id/11290703-L.jpg', 4.1, '9786075694573', 'es', 288),
('Sapiens: De animales a dioses', 'Yuval Noah Harari', 'La historia completa de cómo pasamos de simios a especie dominante. Provocador y adictivo.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8634250-L.jpg', 4.6, '9782226479822', 'es', 496),
('Homo Deus', 'Yuval Noah Harari', 'Vencimos el hambre, la peste y la guerra. Lo que la humanidad hará ahora te va a inquietar.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8846275-L.jpg', 4.4, '9780062834317', 'es', 496),
('Armas, gérmenes y acero', 'Jared Diamond', 'Por qué unos continentes conquistaron a otros: geografía, vacas y bacterias, no superioridad.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7884018-L.jpg', 4.3, '9787532739233', 'es', 592),
('SPQR', 'Mary Beard', 'Mil años de Roma contados sin mármol ni solemnidad: política sucia, memes antiguos y gente real.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7390155-L.jpg', 4.3, '9788498929553', 'es', 656),
('Rubicón', 'Tom Holland', 'El auge y suicidio de la República romana. César cruza un río y ya nada vuelve a ser igual.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/2380298-L.jpg', 4.4, '9780316861304', 'es', 480),
('La Segunda Guerra Mundial', 'Antony Beevor', 'La guerra completa en un solo volumen brutal y humano. Beevor no te ahorra nada.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7239351-L.jpg', 4.5, '9780297860709', 'es', 1200),
('Auschwitz: Los nazis y la solución final', 'Laurence Rees', 'Cómo se construye el infierno paso a paso, con testimonios de víctimas y verdugos.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/375389-L.jpg', 4.5, '9789151847535', 'es', 464),
('Breve historia del mundo', 'Ernst H. Gombrich', 'Toda la historia humana contada como un cuento para su nieta. Imposible de soltar a cualquier edad.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13537590-L.jpg', 4.4, '9788411001526', 'es', 336),
('Postguerra', 'Tony Judt', 'Europa desde 1945: cómo un continente en ruinas se reinventó sin resolver sus fantasmas.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12338006-L.jpg', 4.5, '9788430606108', 'es', 1200),
('Los cañones de agosto', 'Barbara W. Tuchman', 'Los treinta días de errores en cadena que convirtieron un asesinato en la Primera Guerra Mundial.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6616967-L.jpg', 4.4, '9788490061626', 'es', 608),
('Visión de los vencidos', 'Miguel León-Portilla', 'La conquista de México contada por los aztecas. La otra mitad de la historia que no te enseñaron.', ARRAY['Historia'], ARRAY[]::text[], NULL, 4.5, NULL, 'es', 240),
('Historia verdadera de la conquista de la Nueva España', 'Bernal Díaz del Castillo', 'Un soldado de Cortés lo vio todo y lo contó sin filtro cincuenta años después. Crónica monumental.', ARRAY['Historia','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5858039-L.jpg', 4.3, '9781108017077', 'es', 736),
('Las venas abiertas de América Latina', 'Eduardo Galeano', 'Cinco siglos de saqueo contados con rabia y poesía. El libro más polémico del continente.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5416334-L.jpg', 4.4, '9789682310201', 'es', 384),
('El espejo enterrado', 'Carlos Fuentes', 'Fuentes recorre quinientos años de cultura hispanoamericana buscando qué somos a ambos lados del océano.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12836674-L.jpg', 4.2, '9786071106148', 'es', 448),
('México profundo', 'Guillermo Bonfil Batalla', 'Hay un México imaginario que gobierna y un México profundo, mesoamericano, que resiste. Lectura esencial.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4992664-L.jpg', 4.4, '9789684199293', 'es', 256),
('La otra historia de los Estados Unidos', 'Howard Zinn', 'EE.UU. contado desde abajo: esclavos, obreras, nativos y todos los que el mito borra.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10592817-L.jpg', 4.4, '9781565843790', 'es', 768),
('Genghis Khan y el inicio del mundo moderno', 'Jack Weatherford', 'El bárbaro que conquistó más tierra que nadie e inventó la globalización sin querer.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/390818-L.jpg', 4.3, '9780609610626', 'es', 400),
('Historia del siglo XX', 'Eric Hobsbawm', 'De Sarajevo 1914 a la caída de la URSS: el siglo corto que lo cambió todo, por su mejor historiador.', ARRAY['Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13619209-L.jpg', 4.4, '9788484320425', 'es', 624),
('Sobre la tiranía', 'Timothy Snyder', 'Veinte lecciones del siglo XX para no repetirlo. Corto, urgente y más vigente cada año.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10186935-L.jpg', 4.3, '9780593666548', 'es', 128),
('El infinito en un junco', 'Irene Vallejo', 'La historia del libro: bibliotecas incendiadas, copistas rebeldes y por qué leer sigue siendo un milagro.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9689877-L.jpg', 4.7, '9788830105102', 'es', 456);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('Una historia de España', 'Arturo Pérez-Reverte', 'España entera contada a navajazos de ironía en capítulos de tres páginas. Vas a reír y a indignarte.', ARRAY['Historia','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8362403-L.jpg', 4.2, '9788420438177', 'es', 256),
('Historia mínima de México', 'Daniel Cosío Villegas', 'De los olmecas al siglo XX en un volumen breve del Colegio de México. La referencia esencial.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4217432-L.jpg', 4.1, '9789681200954', 'es', 224),
('HHhH', 'Laurent Binet', 'La operación para asesinar a Heydrich, el nazi más peligroso, contada por un narrador obsesionado con la verdad.', ARRAY['Historia','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13279649-L.jpg', 4.3, '9781448155149', 'es', 400),
('Los pilares de la Tierra', 'Ken Follett', 'Construir una catedral en la Edad Media: cinco décadas de ambición, traición y arquitectura épica.', ARRAY['Historia','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12331263-L.jpg', 4.6, '9789506445393', 'es', 1088),
('La catedral del mar', 'Ildefonso Falcones', 'Un siervo fugitivo prospera en la Barcelona medieval mientras la Inquisición le pisa los talones.', ARRAY['Historia','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6596163-L.jpg', 4.4, '9788425340031', 'es', 672),
('Sinuhé, el egipcio', 'Mika Waltari', 'Las memorias de un médico en el Egipto de los faraones. La novela histórica perfecta, punto.', ARRAY['Historia','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1048737-L.jpg', 4.6, '9788497596657', 'es', 800),
('Yo, Claudio', 'Robert Graves', 'El tonto de la familia imperial sobrevive a todos los venenos y escribe la verdad sobre Roma.', ARRAY['Historia','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13486265-L.jpg', 4.5, '9788491819110', 'es', 544),
('Memorias de Adriano', 'Marguerite Yourcenar', 'Un emperador moribundo le escribe a su sucesor sobre el poder, el amor y la muerte. Prosa perfecta.', ARRAY['Historia','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15015608-L.jpg', 4.5, NULL, 'es', 320),
('El tiempo entre costuras', 'María Dueñas', 'Una modista española cose alta costura y espía para los ingleses en el Marruecos de la guerra.', ARRAY['Historia','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6665280-L.jpg', 4.4, '9788467239928', 'es', 640),
('Un día en la antigua Roma', 'Alberto Angela', '24 horas en Roma imperial: desde el desayuno hasta las termas. Historia que se siente turismo.', ARRAY['Historia','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14018337-L.jpg', 4.3, '9788491647270', 'es', 448),
('El diario de Ana Frank', 'Ana Frank', 'Una adolescente escondida de los nazis escribe sobre miedo, primeras veces y esperanza. Imprescindible.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12934565-L.jpg', 4.6, '9789685146074', 'es', 400),
('Steve Jobs', 'Walter Isaacson', 'El genio insoportable que cambió seis industrias, contado sin censura por el biógrafo que él mismo eligió.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12374726-L.jpg', 4.4, '9788499921181', 'es', 736),
('Leonardo da Vinci', 'Walter Isaacson', 'El hombre más curioso de la historia: anatomista, inventor, pintor y procrastinador serial.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8087691-L.jpg', 4.4, '9781508267294', 'es', 624),
('Una vida en nuestro planeta', 'David Attenborough', 'El testigo de 90 años que vio al planeta romperse y su plan para arreglarlo antes del final.', ARRAY['Biografía','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11270248-L.jpg', 4.5, '9788491993117', 'es', 272),
('Yo soy Malala', 'Malala Yousafzai', 'Le dispararon por ir a la escuela. Sobrevivió y su voz se volvió más fuerte que el miedo.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12806375-L.jpg', 4.4, '9786074386783', 'es', 368),
('El largo camino hacia la libertad', 'Nelson Mandela', '27 años preso y salió sin odio a liberar a su país. La autobiografía del siglo XX.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12702407-L.jpg', 4.6, '9780316641067', 'es', 768),
('Mi historia', 'Michelle Obama', 'Del sur de Chicago a la Casa Blanca sin perderse a sí misma. Honesta hasta donde duele.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8824664-L.jpg', 4.5, '9788418594373', 'es', 464),
('Persépolis', 'Marjane Satrapi', 'Crecer durante la revolución iraní, en viñetas en blanco y negro que golpean más que mil fotos.', ARRAY['Biografía','Historia'], ARRAY['Novela gráfica'], 'https://covers.openlibrary.org/b/id/12648921-L.jpg', 4.5, '9788417910150', 'es', 368),
('Elon Musk', 'Ashlee Vance', 'El retrato sin filtros del hombre que apuesta la fortuna entera cada vez que se aburre.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8463846-L.jpg', 4.2, '9780241430903', 'es', 400),
('Confesiones de un chef', 'Anthony Bourdain', 'Drogas, cuchillos y verdades incómodas de las cocinas profesionales. El libro que destapó la industria.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3359248-L.jpg', 4.3, '9788478713738', 'es', 384),
('Open', 'Andre Agassi', 'El mejor tenista del mundo odiaba el tenis. La autobiografía deportiva más honesta jamás escrita.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6714053-L.jpg', 4.6, '9780007346301', 'es', 448),
('Nunca te pares', 'Phil Knight', 'Vendía tenis desde la cajuela de su coche. Casi quiebra cien veces antes de llamarse Nike.', ARRAY['Biografía','Educación'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8858487-L.jpg', 4.5, '9781534415201', 'es', 400),
('La ridícula idea de no volver a verte', 'Rosa Montero', 'Montero lee el diario de Marie Curie y escribe sobre el duelo, la ciencia y las mujeres que arden.', ARRAY['Biografía','Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7258972-L.jpg', 4.3, '9788432239939', 'es', 240),
('Frida: una biografía de Frida Kahlo', 'Hayden Herrera', 'La vida completa de Frida: el accidente, Diego, el dolor convertido en arte y mito.', ARRAY['Biografía','Arte'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4358223-L.jpg', 4.4, '9789681316846', 'es', 528),
('Instrumental', 'James Rhodes', 'La música clásica le salvó la vida a un sobreviviente de abuso. Crudo, furioso y luminoso.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11011479-L.jpg', 4.3, '9781782113379', 'es', 288),
('El hombre en busca de sentido', 'Viktor E. Frankl', 'Un psiquiatra sobrevive Auschwitz y descubre qué mantiene vivas a las personas cuando todo falta.', ARRAY['Biografía','Filosofía','Psicología'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11203708-L.jpg', 4.7, '9780807067994', 'es', 168),
('Una educación', 'Tara Westover', 'Creció sin escuela en una familia mormona extremista. Terminó con un doctorado en Cambridge. Historia real.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8314077-L.jpg', 4.6, '9786160834556', 'es', 400),
('Cuando el aire se acaba', 'Paul Kalanithi', 'Un neurocirujano de 36 años recibe el diagnóstico que él mismo daba. Escribe hasta el final.', ARRAY['Biografía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11463139-L.jpg', 4.6, '9780812988413', 'es', 256),
('Vivir para contarla', 'Gabriel García Márquez', 'García Márquez cuenta su propia infancia: los abuelos, los fantasmas y el pueblo que sería Macondo.', ARRAY['Biografía','Realismo Mágico'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10097398-L.jpg', 4.4, '9783462030280', 'es', 528),
('Confieso que he vivido', 'Pablo Neruda', 'Las memorias del poeta: consulados remotos, amores, política y una vida vivida en tamaño épico.', ARRAY['Biografía','Poesía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1048424-L.jpg', 4.4, '9789500371940', 'es', 512),
('Cleopatra', 'Stacy Schiff', 'Ni el mito ni la propaganda romana: la política más hábil del mundo antiguo, restaurada con lupa.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7083366-L.jpg', 4.2, '9781448114719', 'es', 432),
('Alexander Hamilton', 'Ron Chernow', 'El huérfano inmigrante que diseñó el sistema financiero de EE.UU. y murió en un duelo. Sí, el del musical.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8261375-L.jpg', 4.5, '9780147501554', 'es', 832),
('Churchill: la biografía', 'Andrew Roberts', 'Mil páginas del hombre que sostuvo solo la guerra contra Hitler, con todos sus defectos monumentales.', ARRAY['Biografía','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10085040-L.jpg', 4.5, '9781784385132', 'es', 1152),
('Diarios de motocicleta', 'Ernesto Che Guevara', 'Dos amigos cruzan Sudamérica en una moto destartalada. Uno de ellos volverá convertido en otra persona.', ARRAY['Biografía','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/923234-L.jpg', 4.2, '9781876175702', 'es', 224),
('Van Gogh: la vida', 'Steven Naifeh y Gregory White Smith', 'Diez años de investigación sobre el pintor que vendió un cuadro en vida y hoy vale millones.', ARRAY['Biografía','Arte'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10715967-L.jpg', 4.4, '9781588360472', 'es', 1104),
('Don Quijote de la Mancha', 'Miguel de Cervantes', 'Un señor lee tantas novelas de caballería que decide volverse caballero. La primera novela moderna y la mejor.', ARRAY['Clásicos','Aventura','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14428305-L.jpg', 4.5, '9780786181797', 'es', 1248),
('Crimen y castigo', 'Fiódor Dostoievski', 'Un estudiante mata a una usurera para probar que puede. Su conciencia tiene otros planes.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12328823-L.jpg', 4.7, '9788420665658', 'es', 672),
('Los hermanos Karamázov', 'Fiódor Dostoievski', 'Tres hermanos, un padre asesinado y todas las grandes preguntas sobre Dios y la libertad.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11609759-L.jpg', 4.7, '9781539427759', 'es', 1008),
('Anna Karénina', 'León Tolstói', 'Una mujer casada de la alta sociedad rusa se enamora de otro. El tren del inicio no es casualidad.', ARRAY['Clásicos','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/2560652-L.jpg', 4.6, '9798669140557', 'es', 1040),
('Guerra y paz', 'León Tolstói', 'Napoleón invade Rusia y cinco familias viven amor, guerra y ruina. La novela total.', ARRAY['Clásicos','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13859412-L.jpg', 4.6, '9788439710318', 'es', 1440),
('Madame Bovary', 'Gustave Flaubert', 'Emma quiere la vida de las novelas románticas que lee. La realidad le va a cobrar la diferencia.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12993424-L.jpg', 4.4, '9798589232837', 'es', 400),
('Los miserables', 'Victor Hugo', 'Un expresidiario busca redención mientras un policía lo caza por décadas. Justicia, amor y barricadas.', ARRAY['Clásicos','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12733432-L.jpg', 4.7, '9788491041542', 'es', 1664),
('Grandes esperanzas', 'Charles Dickens', 'Un huérfano recibe una fortuna de un benefactor anónimo. Descubrir quién es lo destruirá.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12460173-L.jpg', 4.4, '9788417563332', 'es', 544),
('Historia de dos ciudades', 'Charles Dickens', 'Londres y París durante la Revolución Francesa, y el sacrificio más famoso de la literatura.', ARRAY['Clásicos','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14565295-L.jpg', 4.5, NULL, 'es', 448),
('Moby Dick', 'Herman Melville', 'Un capitán obsesionado persigue a la ballena blanca que le arrancó la pierna. La obsesión como naufragio.', ARRAY['Clásicos','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10544254-L.jpg', 4.3, '9780671019129', 'es', 704),
('El gran Gatsby', 'F. Scott Fitzgerald', 'Fiestas legendarias, una luz verde al otro lado de la bahía y el sueño americano pudriéndose en oro.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13479285-L.jpg', 4.4, '9788429761221', 'es', 224),
('Matar a un ruiseñor', 'Harper Lee', 'Una niña ve a su padre defender a un inocente en un pueblo que ya lo condenó por negro.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13628885-L.jpg', 4.7, '9781681419770', 'es', 400),
('El guardián entre el centeno', 'J.D. Salinger', 'Holden Caulfield, expulsado y furioso, vaga por Nueva York odiando a los falsos. Lo entenderás demasiado.', ARRAY['Clásicos','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9273490-L.jpg', 4.3, '9780241988794', 'es', 288),
('En el camino', 'Jack Kerouac', 'Jazz, carreteras infinitas y libertad desesperada. El libro que inventó el road trip como religión.', ARRAY['Clásicos','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12482326-L.jpg', 4.1, '9788433959485', 'es', 384),
('Ulises', 'James Joyce', 'Un día entero en Dublín convertido en el Everest de la literatura. Subirlo cambia cómo lees todo.', ARRAY['Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10540228-L.jpg', 4.1, '9788432220128', 'es', 912);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('La metamorfosis', 'Franz Kafka', 'Gregor despierta convertido en insecto y su familia lo trata... como siempre lo trató.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14073660-L.jpg', 4.4, '9788497942027', 'es', 128),
('El proceso', 'Franz Kafka', 'Lo arrestan una mañana sin decirle por qué. Nadie lo sabe. El sistema tampoco. Pesadilla perfecta.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14910748-L.jpg', 4.4, NULL, 'es', 304),
('El extranjero', 'Albert Camus', 'Meursault no llora en el funeral de su madre. La sociedad se lo cobrará más que el crimen.', ARRAY['Clásicos','Filosofía'], ARRAY['Existencialismo'], 'https://covers.openlibrary.org/b/id/15070895-L.jpg', 4.5, NULL, 'es', 160),
('La peste', 'Albert Camus', 'Una ciudad en cuarentena y un médico que pelea sin esperanza ni rendición. Se leyó distinto después de 2020.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13151272-L.jpg', 4.5, '9798687341165', 'es', 352),
('El lobo estepario', 'Hermann Hesse', 'Un intelectual dividido entre hombre y lobo entra a un teatro mágico: solo para locos.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14592521-L.jpg', 4.4, '9789700769523', 'es', 304),
('Demian', 'Hermann Hesse', 'Un adolescente conoce a alguien que le enseña a romper el mundo que le enseñaron. Rito de paso total.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12569297-L.jpg', 4.5, '9788804667919', 'es', 224),
('El retrato de Dorian Gray', 'Oscar Wilde', 'Él permanece joven y bello; su retrato envejece y se pudre con cada pecado. Hasta que lo mira.', ARRAY['Clásicos','Terror'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/8061086-L.jpg', 4.5, '9781512006209', 'es', 304),
('El viejo y el mar', 'Ernest Hemingway', 'Un pescador viejo, un pez gigante y tres días de pelea en el mar. Nadie escribe más con menos.', ARRAY['Clásicos','Aventura'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14289984-L.jpg', 4.4, '9781541324565', 'es', 128),
('Las uvas de la ira', 'John Steinbeck', 'Una familia pierde su tierra y cruza el país persiguiendo trabajo que no existe. Furia hecha novela.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12715902-L.jpg', 4.5, '9780749303273', 'es', 608),
('De ratones y hombres', 'John Steinbeck', 'Dos jornaleros sueñan con una granja propia. George cuida de Lennie, que no conoce su propia fuerza.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14319003-L.jpg', 4.5, '9781517444853', 'es', 128),
('Mujercitas', 'Louisa May Alcott', 'Cuatro hermanas crecen durante la guerra civil. Jo March lleva 150 años inspirando escritoras.', ARRAY['Clásicos','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13012019-L.jpg', 4.4, '9788408216636', 'es', 656),
('La Odisea', 'Homero', 'Diez años para volver a casa esquivando cíclopes, sirenas y dioses rencorosos. El viaje original.', ARRAY['Clásicos','Aventura'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/13180792-L.jpg', 4.5, '9781505595161', 'es', 448),
('La Ilíada', 'Homero', 'La ira de Aquiles en la guerra de Troya. Honor, dioses y la muerte cara a cara.', ARRAY['Clásicos'], ARRAY['Mitología'], 'https://covers.openlibrary.org/b/id/643208-L.jpg', 4.4, '9789706272812', 'es', 576),
('La Divina Comedia', 'Dante Alighieri', 'Dante baja al infierno círculo por círculo, con nombres y apellidos de sus enemigos. Venganza literaria épica.', ARRAY['Clásicos','Poesía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/15188866-L.jpg', 4.4, '9788422606192', 'es', 928),
('Hamlet', 'William Shakespeare', 'El fantasma de tu padre te pide venganza. Pensarlo demasiado también es una tragedia.', ARRAY['Clásicos','Drama'], ARRAY['Teatro'], 'https://covers.openlibrary.org/b/id/8281954-L.jpg', 4.5, '9781976146930', 'es', 320),
('Romeo y Julieta', 'William Shakespeare', 'Dos familias en guerra, dos adolescentes enamorados, cinco días de caos. Sabes el final y duele igual.', ARRAY['Clásicos','Romance'], ARRAY['Teatro'], 'https://covers.openlibrary.org/b/id/13818614-L.jpg', 4.4, '9781985716551', 'es', 288),
('Fausto', 'Johann Wolfgang von Goethe', 'Un sabio le vende el alma al diablo a cambio de un solo momento perfecto. El trato más famoso.', ARRAY['Clásicos','Filosofía'], ARRAY['Teatro'], 'https://covers.openlibrary.org/b/id/13480127-L.jpg', 4.3, '9788491051947', 'es', 560),
('Las penas del joven Werther', 'Johann Wolfgang von Goethe', 'Un joven se enamora de una mujer comprometida y lo escribe todo. El libro que incendió Europa.', ARRAY['Clásicos','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13188078-L.jpg', 4.2, '9788424923563', 'es', 192),
('Papá Goriot', 'Honoré de Balzac', 'Un padre lo da todo por hijas que lo abandonan, y un joven ambicioso aprende cómo funciona París.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8237944-L.jpg', 4.3, '9786055904708', 'es', 368),
('Rojo y negro', 'Stendhal', 'Un carpintero brillante escala la sociedad francesa usando seducción y sotana. La ambición como novela.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13484780-L.jpg', 4.3, '9788446046431', 'es', 656),
('La casa de Bernarda Alba', 'Federico García Lorca', 'Ocho años de luto encerradas por orden de la madre. Cinco hijas y una olla a presión.', ARRAY['Clásicos','Drama'], ARRAY['Teatro'], 'https://covers.openlibrary.org/b/id/7323388-L.jpg', 4.4, '9788423918775', 'es', 144),
('La Regenta', 'Leopoldo Alas Clarín', 'Una mujer asfixiada en una ciudad de provincias, disputada entre un canónigo y un donjuán. Obra maestra.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5749155-L.jpg', 4.3, '9788497936620', 'es', 928),
('Fortunata y Jacinta', 'Benito Pérez Galdós', 'Dos mujeres aman al mismo inútil en el Madrid del XIX. Galdós lo ve todo y no perdona nada.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3866770-L.jpg', 4.3, '9788437604381', 'es', 1088),
('Niebla', 'Miguel de Unamuno', 'Augusto descubre que es un personaje de novela y va a reclamarle a Unamuno en persona. En serio.', ARRAY['Clásicos','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/147489-L.jpg', 4.3, '9781983530647', 'es', 304),
('El túnel', 'Ernesto Sabato', 'Un pintor confiesa desde el principio que mató a la única persona que podía entenderlo. Obsesión pura.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5517733-L.jpg', 4.5, '9780141194547', 'es', 160),
('Ficciones', 'Jorge Luis Borges', 'Bibliotecas infinitas, laberintos, mapas del tamaño del mundo. Diecisiete cuentos que doblan la realidad.', ARRAY['Clásicos','Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10832290-L.jpg', 4.7, '9780802190734', 'es', 224),
('El Aleph', 'Jorge Luis Borges', 'Un punto del sótano contiene todos los puntos del universo. Borges en su máxima potencia.', ARRAY['Clásicos','Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14408958-L.jpg', 4.7, '9789772830497', 'es', 224),
('Rayuela', 'Julio Cortázar', 'Una novela que puedes leer en dos órdenes distintos. París, jazz, La Maga y el amor como laberinto.', ARRAY['Clásicos','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1047466-L.jpg', 4.5, '9788402067401', 'es', 736),
('La ciudad y los perros', 'Mario Vargas Llosa', 'Cadetes de un colegio militar limeño sobreviven a base de violencia y códigos. Un robo lo rompe todo.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3221667-L.jpg', 4.4, '9788954682350', 'es', 480),
('Doña Bárbara', 'Rómulo Gallegos', 'La devoradora de hombres reina sobre el llano venezolano hasta que llega un abogado con otros planes.', ARRAY['Clásicos','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/3743483-L.jpg', 4.2, '9788423919765', 'es', 368),
('Los detectives salvajes', 'Roberto Bolaño', 'Dos poetas persiguen a una escritora desaparecida durante veinte años y tres continentes. Culto absoluto.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], NULL, 4.5, NULL, 'es', 624),
('2666', 'Roberto Bolaño', 'Cinco novelas en una que orbitan los asesinatos de mujeres en la frontera. Monumental y oscura.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1047310-L.jpg', 4.4, '9788702089578', 'es', 1128),
('Tokio blues', 'Haruki Murakami', 'Un estudiante entre dos mujeres: una atada a la muerte, otra desbordante de vida. Melancolía perfecta.', ARRAY['Novela Contemporánea','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13589200-L.jpg', 4.3, '9788490667071', 'es', 384),
('Kafka en la orilla', 'Haruki Murakami', 'Un chico de quince años huye de casa y un anciano habla con gatos. Sus caminos doblan la realidad.', ARRAY['Novela Contemporánea','Realismo Mágico'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/4982600-L.jpg', 4.4, '9789871544189', 'es', 592),
('La insoportable levedad del ser', 'Milan Kundera', 'Cuatro vidas cruzadas en la Praga del 68: amor, sexo y la pregunta de si algo pesa de verdad.', ARRAY['Novela Contemporánea','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13184405-L.jpg', 4.4, '9788490667026', 'es', 336),
('El lector', 'Bernhard Schlink', 'A los quince se enamora de una mujer mayor que desaparece. La reencuentra años después: en un juicio nazi.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/998445-L.jpg', 4.2, '9780783886466', 'es', 208),
('Las vírgenes suicidas', 'Jeffrey Eugenides', 'Cinco hermanas encerradas por sus padres y los chicos del barrio que nunca dejaron de pensarlas.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/486854-L.jpg', 4.1, '9780446670258', 'es', 256),
('Expiación', 'Ian McEwan', 'Una niña de trece años cuenta una mentira que destroza tres vidas. Pasa la vida entera pagándola.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12331363-L.jpg', 4.3, '9788433902580', 'es', 448),
('La campana de cristal', 'Sylvia Plath', 'Una becaria brillante en Nueva York siente que se asfixia bajo una campana invisible. Autobiográfica y feroz.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8477115-L.jpg', 4.3, '9788423991235', 'es', 288),
('Conversaciones entre amigos', 'Sally Rooney', 'Dos exnovias poetas se enredan con un matrimonio mayor. Nadie sale sin quemarse.', ARRAY['Novela Contemporánea','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8199499-L.jpg', 4, '9781510059245', 'es', 336),
('La chica salvaje', 'Delia Owens', 'La niña que creció sola en el pantano es la principal sospechosa cuando el chico popular aparece muerto.', ARRAY['Novela Contemporánea','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8362947-L.jpg', 4.5, '9782757889978', 'es', 384),
('Un hombre llamado Ove', 'Fredrik Backman', 'El vecino más gruñón del mundo tiene un plan para morirse. Sus vecinos nuevos se lo arruinan a diario.', ARRAY['Novela Contemporánea','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7437001-L.jpg', 4.5, '9788490624890', 'es', 368),
('Mi año de descanso y relajación', 'Ottessa Moshfegh', 'Una joven con todo a favor decide dormir un año entero a base de pastillas. Oscuramente hilarante.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8202400-L.jpg', 4, '9780525631934', 'es', 304),
('La amiga estupenda', 'Elena Ferrante', 'Dos niñas en un barrio pobre de Nápoles compiten y se salvan mutuamente durante toda una vida.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13772133-L.jpg', 4.4, '9781609459468', 'es', 400),
('Pachinko', 'Min Jin Lee', 'Cuatro generaciones de una familia coreana en Japón: apostarlo todo en un país que no te quiere.', ARRAY['Novela Contemporánea','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8044605-L.jpg', 4.4, '9781668648315', 'es', 560),
('Los siete maridos de Evelyn Hugo', 'Taylor Jenkins Reid', 'Una diva de Hollywood confiesa la verdad de sus siete matrimonios. El secreto no es ninguno de ellos.', ARRAY['Novela Contemporánea','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8354226-L.jpg', 4.6, '9781683244646', 'es', 448),
('Todos quieren a Daisy Jones', 'Taylor Jenkins Reid', 'La banda más grande de los setenta se separó en pleno éxito. Cincuenta años después, hablan todos.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8742674-L.jpg', 4.4, '9781787462144', 'es', 432),
('Todo lo que no te dije', 'Celeste Ng', 'Lydia apareció en el lago y cada miembro de su familia cree saber por qué. Todos se equivocan.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7383473-L.jpg', 4.2, '9780349134291', 'es', 304),
('Americanah', 'Chimamanda Ngozi Adichie', 'Una nigeriana descubre en EE.UU. que ahora es ''negra''. Años después vuelve por el amor que dejó.', ARRAY['Novela Contemporánea','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8474037-L.jpg', 4.4, '9781410486134', 'es', 608),
('El curioso incidente del perro a medianoche', 'Mark Haddon', 'Un chico autista investiga la muerte del perro del vecino y destapa algo mucho más grande.', ARRAY['Novela Contemporánea','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13654116-L.jpg', 4.3, NULL, 'es', 288);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
('La ladrona de libros', 'Markus Zusak', 'La Muerte narra la historia de una niña que roba libros en la Alemania nazi. Sí, la Muerte narra.', ARRAY['Novela Contemporánea','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8153054-L.jpg', 4.6, '9781407037219', 'es', 544),
('El niño con el pijama de rayas', 'John Boyne', 'El hijo de un comandante nazi hace un amigo al otro lado de la cerca. No sabes lo que viene.', ARRAY['Novela Contemporánea','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12720687-L.jpg', 4.3, '9780385610551', 'es', 224),
('Las ventajas de ser invisible', 'Stephen Chbosky', 'Charlie escribe cartas sobre su primer año de prepa: amigos, mixtapes y heridas que no nombra.', ARRAY['Novela Contemporánea','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14315052-L.jpg', 4.4, '9785389061606', 'es', 256),
('La lección de August', 'R.J. Palacio', 'August entra a quinto grado con una cara que hace voltear a todos. Elige ser amable. Siempre.', ARRAY['Novela Contemporánea','Juvenil'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12340591-L.jpg', 4.5, '9789871997015', 'es', 416),
('Eleanor Oliphant está perfectamente', 'Gail Honeyman', 'Eleanor tiene rutinas perfectas, cero amigos y un pasado que no cuenta. Está perfectamente. Hasta que no.', ARRAY['Novela Contemporánea','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14682699-L.jpg', 4.4, '9788416859115', 'es', 400),
('La elegancia del erizo', 'Muriel Barbery', 'Una portera que esconde su genialidad y una niña que planea suicidarse a los trece. Se encuentran.', ARRAY['Novela Contemporánea','Filosofía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6280314-L.jpg', 4.3, '9788432228216', 'es', 368),
('Seda', 'Alessandro Baricco', 'Un comerciante francés viaja a Japón por gusanos de seda y una mirada le cambia la vida. Brevísimo y perfecto.', ARRAY['Novela Contemporánea','Romance'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10856789-L.jpg', 4.2, '9788447315307', 'es', 128),
('El club de la buena estrella', 'Amy Tan', 'Cuatro madres chinas y sus hijas americanas: todo lo que se pierde y se hereda entre dos mundos.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14155747-L.jpg', 4.2, '9788408196532', 'es', 352),
('Cometas en el cielo', 'Khaled Hosseini', 'Dos niños inseparables en Kabul, una traición imperdonable y una vida entera buscando redimirla.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/11177899-L.jpg', 4.6, '9788478888856', 'es', 400),
('Mil soles espléndidos', 'Khaled Hosseini', 'Dos mujeres afganas unidas por la guerra y un esposo brutal. Te va a destrozar y reconstruir.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12325850-L.jpg', 4.6, '9788498381351', 'es', 416),
('Como polvo en el viento', 'Leonardo Padura', 'Un grupo de amigos cubanos se dispersa por el mundo durante décadas. El exilio como herida compartida.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10398030-L.jpg', 4.3, '9788490668610', 'es', 672),
('Temporada de huracanes', 'Fernanda Melchor', 'Aparece muerta la Bruja del pueblo y cada voz cuenta su versión. Prosa huracanada, literal.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10354466-L.jpg', 4.2, '9783803142467', 'es', 224),
('Las batallas en el desierto', 'José Emilio Pacheco', 'Carlitos se enamora de la mamá de su mejor amigo en el México de los cuarenta. Breve y eterno.', ARRAY['Novela Contemporánea','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5436924-L.jpg', 4.4, '9789684110526', 'es', 68),
('Distancia de rescate', 'Samanta Schweblin', 'Una mujer moribunda reconstruye con un niño ajeno cómo llegó ahí. Inquietud pura en cien páginas.', ARRAY['Novela Contemporánea','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7395966-L.jpg', 4.1, '9780399184604', 'es', 128),
('Mandíbula', 'Mónica Ojeda', 'Colegialas obsesionadas con el terror y una profesora al borde. El horror adolescente hecho literatura.', ARRAY['Novela Contemporánea','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13010025-L.jpg', 4, '9781566896214', 'es', 288),
('Los ingrávidos', 'Valeria Luiselli', 'Una escritora en México y un poeta en Harlem se escriben a través del tiempo. Fantasmal y bellísima.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8092107-L.jpg', 4.1, '9786077781424', 'es', 160),
('Canción dulce', 'Leïla Slimani', 'La niñera perfecta existe y la primera página te dice lo que hizo. Igual no puedes parar.', ARRAY['Novela Contemporánea','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13099687-L.jpg', 4, '9780571342464', 'es', 240),
('La vegetariana', 'Han Kang', 'Una mujer deja de comer carne y su decisión detona a toda su familia. Nobel y perturbadora.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13572043-L.jpg', 4.1, '9788416738120', 'es', 192),
('Los restos del día', 'Kazuo Ishiguro', 'Un mayordomo inglés repasa su vida de lealtad perfecta y descubre todo lo que dejó pasar.', ARRAY['Novela Contemporánea','Drama'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/95742-L.jpg', 4.4, '9788806134815', 'es', 256),
('Kim Ji-young, nacida en 1982', 'Cho Nam-joo', 'La vida entera de una mujer coreana común. Tan común que incendió un país entero.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9338903-L.jpg', 4.2, '9781631498671', 'es', 176),
('Beloved', 'Toni Morrison', 'Una esclava fugitiva es perseguida por el fantasma de la hija que no dejó volver a la esclavitud.', ARRAY['Novela Contemporánea','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8261367-L.jpg', 4.4, '9785699874958', 'es', 352),
('El color púrpura', 'Alice Walker', 'Celie escribe cartas a Dios porque no tiene a nadie más. Hasta que aprende a escribirse a sí misma.', ARRAY['Novela Contemporánea','Clásicos'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14092160-L.jpg', 4.5, '9788466360906', 'es', 304),
('La conjura de los necios', 'John Kennedy Toole', 'Ignatius J. Reilly, genio autoproclamado y desastre humano, sale a trabajar por primera vez. Nueva Orleans tiembla.', ARRAY['Novela Contemporánea','Humor'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/13756269-L.jpg', 4.4, '9788447360949', 'es', 416),
('Trainspotting', 'Irvine Welsh', 'Heroína, amistad tóxica y furia en el Edimburgo de los ochenta. Elige la vida, o no.', ARRAY['Novela Contemporánea'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/6673876-L.jpg', 4.1, '9780749333331', 'es', 448),
('El juego del ángel', 'Carlos Ruiz Zafón', 'Un escritor acepta escribir un libro para un editor misterioso que paga demasiado. Barcelona gótica y trampa.', ARRAY['Novela Contemporánea','Misterio'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/9274818-L.jpg', 4.3, '9788377586532', 'es', 672),
('It', 'Stephen King', 'Algo vive en las alcantarillas de Derry y despierta cada 27 años. Siete niños juraron volver a enfrentarlo.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8569284-L.jpg', 4.6, '9781982127794', 'es', 1504),
('El resplandor', 'Stephen King', 'Un hotel vacío en la montaña, un escritor con demonios y un niño que ve lo que el hotel esconde.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12376585-L.jpg', 4.5, '9788373376052', 'es', 656),
('Cementerio de animales', 'Stephen King', 'Hay un lugar detrás del cementerio de mascotas donde lo enterrado regresa. Pero no regresa igual.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12015500-L.jpg', 4.4, '9782290307762', 'es', 560),
('Drácula', 'Bram Stoker', 'Un abogado visita a un conde en Transilvania. El conde tiene planes para Londres y para su sangre.', ARRAY['Horror','Clásicos','Terror'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/12216503-L.jpg', 4.4, '9780517520178', 'es', 576),
('Frankenstein', 'Mary Shelley', 'Un científico crea vida y huye de ella. Su criatura solo quería que alguien lo mirara sin gritar.', ARRAY['Horror','Clásicos','Ciencia Ficción'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/12356249-L.jpg', 4.5, '9798596021639', 'es', 336),
('El exorcista', 'William Peter Blatty', 'Una niña de doce años empieza a cambiar y la medicina se rinde. Lo que sigue es fe contra el mal.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12715730-L.jpg', 4.3, '9780613913393', 'es', 400),
('La llamada de Cthulhu', 'H.P. Lovecraft', 'Hay cosas dormidas bajo el mar tan antiguas que conocerlas destruye la mente. Alguien las despertó.', ARRAY['Horror','Terror'], ARRAY['Cósmico'], 'https://covers.openlibrary.org/b/id/10477674-L.jpg', 4.4, '9781533390349', 'es', 160),
('En las montañas de la locura', 'H.P. Lovecraft', 'Una expedición antártica encuentra ruinas anteriores a la humanidad. Debieron dejarlas enterradas.', ARRAY['Horror','Terror','Ciencia Ficción'], ARRAY['Cósmico'], 'https://covers.openlibrary.org/b/id/13980068-L.jpg', 4.4, '9788432225161', 'es', 192),
('Narraciones extraordinarias', 'Edgar Allan Poe', 'Corazones que delatan, entierros prematuros y gatos negros. El padre del terror en sus mejores cuentos.', ARRAY['Horror','Clásicos','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/5269500-L.jpg', 4.6, '9789871187263', 'es', 480),
('Otra vuelta de tuerca', 'Henry James', 'Una institutriz jura que fantasmas rondan a los niños que cuida. O ella está perdiendo la cabeza.', ARRAY['Horror','Clásicos'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/181493-L.jpg', 4.1, '9781717348395', 'es', 176),
('Soy leyenda', 'Richard Matheson', 'El último hombre vivo se atrinchera cada noche mientras los infectados gritan su nombre. El final es icónico.', ARRAY['Horror','Ciencia Ficción','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14119685-L.jpg', 4.3, '9788445006764', 'es', 208),
('El extraño caso del Dr. Jekyll y Mr. Hyde', 'Robert Louis Stevenson', 'Un médico respetable inventa la fórmula para liberar su lado oscuro. El problema es volver.', ARRAY['Horror','Clásicos'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/12336384-L.jpg', 4.3, '9789877181388', 'es', 144),
('Entrevista con el vampiro', 'Anne Rice', 'Un vampiro de doscientos años concede una entrevista y confiesa todo: la sangre, la culpa, la eternidad.', ARRAY['Horror','Terror'], ARRAY['Vampiros'], 'https://covers.openlibrary.org/b/id/8401488-L.jpg', 4.3, '9780679447641', 'es', 400),
('La maldición de Hill House', 'Shirley Jackson', 'Cuatro personas pasan el verano en una casa que no está bien construida... ni bien intencionada.', ARRAY['Horror','Terror'], ARRAY['Casas embrujadas'], 'https://covers.openlibrary.org/b/id/4289014-L.jpg', 4.3, '9780140287431', 'es', 304),
('Siempre hemos vivido en el castillo', 'Shirley Jackson', 'Dos hermanas viven aisladas tras el envenenamiento de su familia. Merricat tiene sus rituales. Y sus secretos.', ARRAY['Horror','Misterio'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/7346999-L.jpg', 4.3, '9788495587893', 'es', 224),
('Nuestra parte de noche', 'Mariana Enriquez', 'Un padre médium huye con su hijo de una secta que quiere al niño. Argentina, dictadura y oscuridad.', ARRAY['Horror','Novela Contemporánea','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/10239068-L.jpg', 4.4, '9780593312452', 'es', 672),
('Las cosas que perdimos en el fuego', 'Mariana Enriquez', 'Doce cuentos donde Buenos Aires arde: casas malditas, mujeres en llamas y niños que desaparecen.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7398262-L.jpg', 4.2, '9786051980119', 'es', 208),
('El terror', 'Dan Simmons', 'Dos barcos atrapados en el hielo ártico, tripulación muriendo y algo enorme cazándolos sobre el hielo.', ARRAY['Horror','Historia'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/1174846-L.jpg', 4.3, '9780593057629', 'es', 912),
('Gótico', 'Silvia Moreno-Garcia', 'Una socialité mexicana visita a su prima en una mansión inglesa en las montañas. La casa respira.', ARRAY['Horror','Misterio'], ARRAY['Gótico'], 'https://covers.openlibrary.org/b/id/10239163-L.jpg', 4.2, '9780525620785', 'es', 320),
('La casa al final de Needless Street', 'Catriona Ward', 'Un hombre, una niña y un gato viven al final de la calle. Nada de lo que crees es verdad.', ARRAY['Horror','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/12194637-L.jpg', 4.1, '9788413624501', 'es', 352),
('El ritual', 'Adam Nevill', 'Cuatro amigos toman un atajo por un bosque sueco. Algo antiguo vive ahí y ya los eligió.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/14096799-L.jpg', 4, '9788445014868', 'es', 432),
('NOS4A2', 'Joe Hill', 'Un hombre inmortal secuestra niños hacia Christmasland. Solo una mujer puede encontrar su carretera imposible.', ARRAY['Horror','Fantasía'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/7254564-L.jpg', 4.2, '9780062200570', 'es', 720),
('El otro', 'Thomas Tryon', 'Gemelos idénticos en una granja: uno bueno, uno malo. El horror rural que inspiró a King.', ARRAY['Horror','Terror'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/8481046-L.jpg', 4.1, NULL, 'es', 272),
('Déjame entrar', 'John Ajvide Lindqvist', 'Un niño acosado hace su primera amiga: la vecina que solo sale de noche y huele a muerte.', ARRAY['Horror','Terror'], ARRAY['Vampiros'], 'https://covers.openlibrary.org/b/id/7879453-L.jpg', 4.2, '9788467026658', 'es', 480),
('Ring', 'Koji Suzuki', 'Ves el video, suena el teléfono, tienes siete días. El horror japonés que aterró al mundo.', ARRAY['Horror','Thriller'], ARRAY[]::text[], 'https://covers.openlibrary.org/b/id/958935-L.jpg', 4.1, '9782266121231', 'es', 304);
INSERT INTO books_curated (title, author, description, genres, subgenres, cover_url, rating, isbn, language, pages) VALUES
